CREATE OR REPLACE FUNCTION "public"."custom_access_token_hook"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id uuid;
  v_claims    jsonb;
BEGIN
  v_claims := event -> 'claims';

  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = (event ->> 'user_id')::uuid
    AND type    = 'human'
  LIMIT 1;

  IF v_lenser_id IS NOT NULL THEN
    v_claims := jsonb_set(v_claims, '{lenser_id}', to_jsonb(v_lenser_id));
  END IF;

  RETURN jsonb_set(event, '{claims}', v_claims);
END;
$$;


ALTER FUNCTION "public"."custom_access_token_hook"("event" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."custom_access_token_hook"("event" "jsonb") IS 'Supabase custom access token hook. Embeds lenser_id (human profile UUID) into JWT claims. Register in Dashboard → Auth → Hooks → Custom Access Token.';



CREATE OR REPLACE FUNCTION "public"."fn_accept_follow_request"("p_source_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_target_id uuid;
BEGIN
  SELECT id INTO v_target_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_target_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  UPDATE lensers.relationships
  SET status = 'accepted',
      responded_at = now(),
      accepted_at  = now()
  WHERE source_profile_id = p_source_profile_id
    AND target_profile_id = v_target_id
    AND status = 'pending';

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'reason', 'no_pending_request');
  END IF;

  RETURN jsonb_build_object('success', true);
END;
$$;


ALTER FUNCTION "public"."fn_accept_follow_request"("p_source_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_admin_get_dlq_entries"("p_unresolved_only" boolean DEFAULT true) RETURNS TABLE("id" "uuid", "job_id" "uuid", "battle_id" "uuid", "contender_id" "uuid", "slot" "text", "error_code" "text", "error_message" "text", "attempt_count" integer, "payload" "jsonb", "resolved_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
BEGIN
  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'INSUFFICIENT_PRIVILEGE';
  END IF;
  RETURN QUERY
    SELECT
      d.id, d.job_id, d.battle_id, d.contender_id, d.slot,
      d.error_code, d.error_message, d.attempt_count, d.payload,
      d.resolved_at, d.created_at
    FROM battles.battle_execution_dead_letters d
    WHERE (NOT p_unresolved_only OR d.resolved_at IS NULL)
    ORDER BY d.created_at DESC
    LIMIT 200;
END;
$$;


ALTER FUNCTION "public"."fn_admin_get_dlq_entries"("p_unresolved_only" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_admin_get_stuck_battles"("p_threshold_minutes" integer DEFAULT 30) RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "status" "text", "updated_at" timestamp with time zone, "stale_seconds" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
BEGIN
  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'INSUFFICIENT_PRIVILEGE';
  END IF;
  RETURN QUERY
    SELECT
      b.id,
      b.slug,
      b.title,
      b.status::TEXT,
      b.updated_at,
      ROUND(EXTRACT(EPOCH FROM (now() - b.updated_at))::NUMERIC, 1) AS stale_seconds
    FROM battles.battles b
    WHERE b.status IN ('executing', 'scoring')
      AND b.updated_at < now() - (p_threshold_minutes || ' minutes')::INTERVAL
    ORDER BY b.updated_at ASC;
END;
$$;


ALTER FUNCTION "public"."fn_admin_get_stuck_battles"("p_threshold_minutes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_admin_get_vote_anomalies"("p_status" "text" DEFAULT 'pending'::"text", "p_battle_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 100) RETURNS SETOF "audit"."vote_anomalies"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
BEGIN
  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'Forbidden: super_admin required' USING ERRCODE = 'P0003';
  END IF;

  RETURN QUERY
    SELECT *
      FROM audit.vote_anomalies
     WHERE (
       p_status = 'all'
       OR (p_status = 'pending'  AND resolved_at IS NULL)
       OR (p_status = 'resolved' AND resolved_at IS NOT NULL)
     )
       AND (p_battle_id IS NULL OR battle_id = p_battle_id)
     ORDER BY detected_at DESC
     LIMIT LEAST(p_limit, 500);
END;
$$;


ALTER FUNCTION "public"."fn_admin_get_vote_anomalies"("p_status" "text", "p_battle_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_admin_get_vote_anomalies"("p_status" "text", "p_battle_id" "uuid", "p_limit" integer) IS 'CA: Super-admin list helper for vote anomalies. Used by CLI and admin UI.';



