CREATE OR REPLACE FUNCTION "public"."fn_agent_adapters_register"("p_name" "text", "p_adapter_type" "text", "p_config" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
    v_lenser_id  uuid;
    v_adapter_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'NOT_AUTHENTICATED';
    END IF;

    INSERT INTO agents.adapters (owner_lenser_id, name, adapter_type, config)
    VALUES (v_lenser_id, p_name, p_adapter_type, p_config)
    RETURNING id INTO v_adapter_id;

    RETURN v_adapter_id;
END;
$$;


ALTER FUNCTION "public"."fn_agent_adapters_register"("p_name" "text", "p_adapter_type" "text", "p_config" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_agent_adapters_remove"("p_adapter_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'NOT_AUTHENTICATED';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM agents.adapters
        WHERE id = p_adapter_id AND owner_lenser_id = v_lenser_id
    ) THEN
        RAISE EXCEPTION 'NOT_FOUND_OR_FORBIDDEN';
    END IF;

    UPDATE agents.adapters
    SET is_active = false, updated_at = now()
    WHERE id = p_adapter_id AND owner_lenser_id = v_lenser_id;
END;
$$;


ALTER FUNCTION "public"."fn_agent_adapters_remove"("p_adapter_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_agent_daily_join_count"("p_agent_id" "uuid") RETURNS integer
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'lensers', 'audit', 'public'
    AS $$
  SELECT count(*)::INT
  FROM   audit.events
  WHERE  event_type = 'battle.joined'
  AND    payload->>'agent_id' = p_agent_id::TEXT
  AND    occurred_at >= date_trunc('day', now() AT TIME ZONE 'UTC');
$$;


ALTER FUNCTION "public"."fn_agent_daily_join_count"("p_agent_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_agent_list_subscriptions"("p_agent_id" "uuid") RETURNS TABLE("id" "uuid", "category" "text", "execution_mode" "text", "workflow_id" "uuid", "require_owner_approval" boolean, "max_joins_per_day" integer, "active" boolean, "daily_count" integer, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'agents', 'lensers', 'public'
    AS $$
  SELECT
    bs.id,
    bs.category,
    bs.execution_mode,
    bs.workflow_id,
    bs.require_owner_approval,
    bs.max_joins_per_day,
    bs.active,
    public.fn_agent_daily_join_count(p_agent_id) AS daily_count,
    bs.created_at
  FROM  agents.battle_subscriptions bs
  JOIN  agents.ownerships o ON o.ai_lenser_id = bs.agent_id
  JOIN  lensers.profiles   p ON p.id           = o.owner_lenser_id
  WHERE bs.agent_id = p_agent_id
  AND   o.role IN ('owner', 'co_owner')
  AND   (o.revoked_at IS NULL OR o.revoked_at > now())
  AND   p.user_id = auth.uid()
  ORDER BY bs.created_at DESC;
$$;


ALTER FUNCTION "public"."fn_agent_list_subscriptions"("p_agent_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_agent_run_events"("p_ai_lenser_id" "uuid", "p_run_id" "uuid" DEFAULT NULL::"uuid", "p_event_type" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100) RETURNS TABLE("id" "uuid", "team_run_id" "uuid", "agent_run_step_id" "uuid", "event_type" "text", "payload" "jsonb", "occurred_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
BEGIN
  -- Ownership guard: caller must be the owner or co-owner of this AI lenser.
  -- can_manage_ai_lenser resolves via lensers.get_auth_human_lenser_id(),
  -- which handles workspace-switching (agent_owner mode).
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT
    ev.id,
    ev.team_run_id,
    ev.agent_run_step_id,
    ev.event_type,
    ev.payload,
    ev.occurred_at
  FROM   agents.agent_run_events ev
  JOIN   agents.team_runs        tr ON tr.id = ev.team_run_id
  WHERE  tr.ai_lenser_id = p_ai_lenser_id
    AND  (p_run_id     IS NULL OR ev.team_run_id = p_run_id)
    AND  (p_event_type IS NULL OR ev.event_type  = p_event_type)
  ORDER BY ev.occurred_at DESC
  LIMIT  GREATEST(1, LEAST(COALESCE(p_limit, 100), 500));
END;
$$;


ALTER FUNCTION "public"."fn_agent_run_events"("p_ai_lenser_id" "uuid", "p_run_id" "uuid", "p_event_type" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_agent_run_events"("p_ai_lenser_id" "uuid", "p_run_id" "uuid", "p_event_type" "text", "p_limit" integer) IS 'Owner-only event stream for agents.agent_run_events. Filters by ai_lenser_id via team_runs join. Optional p_run_id and p_event_type narrowing. Authorization via agents.can_manage_ai_lenser (human owner profile). Max 500 rows per call.';



CREATE OR REPLACE FUNCTION "public"."fn_agent_subscribe_to_battles"("p_agent_id" "uuid", "p_category" "text" DEFAULT NULL::"text", "p_execution_mode" "text" DEFAULT 'cloud'::"text", "p_workflow_id" "uuid" DEFAULT NULL::"uuid", "p_require_approval" boolean DEFAULT false, "p_max_joins_per_day" integer DEFAULT 5) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_sub_id    UUID;
BEGIN
  SELECT p.id INTO v_lenser_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  IF NOT EXISTS (
    SELECT 1 FROM agents.ownerships
    WHERE  ai_lenser_id    = p_agent_id
    AND    owner_lenser_id = v_lenser_id
    AND    role IN ('owner', 'co_owner')
  ) THEN
    RAISE EXCEPTION 'subscribe_forbidden: agent not owned by caller';
  END IF;

  INSERT INTO agents.battle_subscriptions (
    agent_id, category, execution_mode, workflow_id,
    require_owner_approval, max_joins_per_day
  )
  VALUES (
    p_agent_id, p_category, p_execution_mode, p_workflow_id,
    p_require_approval, p_max_joins_per_day
  )
  RETURNING id INTO v_sub_id;

  RETURN v_sub_id;
END;
$$;


ALTER FUNCTION "public"."fn_agent_subscribe_to_battles"("p_agent_id" "uuid", "p_category" "text", "p_execution_mode" "text", "p_workflow_id" "uuid", "p_require_approval" boolean, "p_max_joins_per_day" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_agent_unsubscribe_from_battles"("p_subscription_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT p.id INTO v_lenser_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  UPDATE agents.battle_subscriptions bs
  SET    active     = false,
         updated_at = now()
  FROM   agents.ai_lensers al
  JOIN   agents.ownerships  o ON o.ai_lenser_id    = al.id
                              AND o.owner_lenser_id = v_lenser_id
                              AND o.role IN ('owner', 'co_owner')
  WHERE  bs.id    = p_subscription_id
  AND    al.id    = bs.agent_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'unsubscribe_not_found_or_forbidden: %', p_subscription_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_agent_unsubscribe_from_battles"("p_subscription_id" "uuid") OWNER TO "postgres";


