    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'auth'
    AS $$
begin
  return query
  select
    f.product_tag::text,
    f.page,
    f.message,
    f.start_date,
    f.end_date,
