CREATE OR REPLACE FUNCTION "public"."fn_approve_tool_invocation"("p_invocation_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_inv agents.tool_invocations;
BEGIN
  SELECT * INTO v_inv FROM agents.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'invocation not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_inv.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;
  IF v_inv.approval_status <> 'pending' THEN
    RAISE EXCEPTION 'invocation is not pending approval' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.tool_invocations
     SET approval_status     = 'approved',
         approval_decided_by = auth.uid(),
         status              = 'running',
         started_at          = now()
   WHERE id = p_invocation_id;
END;
$$;


ALTER FUNCTION "public"."fn_approve_tool_invocation"("p_invocation_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_assert_modality_allowed"("p_agent_id" "uuid", "p_modality" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'agents', 'public'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM agents.policies ap
    WHERE ap.ai_lenser_id = p_agent_id
      AND p_modality = ANY(ap.allowed_output_modalities)
  ) THEN
    RAISE EXCEPTION 'modality_not_allowed: agent % cannot produce % output. '
      'Update agents.policies.allowed_output_modalities to unlock.', p_agent_id, p_modality
    USING ERRCODE = 'P0001';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_assert_modality_allowed"("p_agent_id" "uuid", "p_modality" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_assert_modality_allowed"("p_agent_id" "uuid", "p_modality" "text") IS 'AP: Raises modality_not_allowed if p_modality is not in agents.policies.allowed_output_modalities for p_agent_id. Called by WorkflowExecutionService before dispatching any non-text generative node. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_assign_lens_to_contender"("p_contender_id" "uuid", "p_battle_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid", "p_input_snapshot" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("id" "uuid", "contender_id" "uuid", "battle_id" "uuid", "lens_id" "uuid", "version_id" "uuid", "assigned_at" timestamp with time zone, "input_snapshot" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
  INSERT INTO battles.contender_lens_assignments
    (contender_id, battle_id, lens_id, version_id, input_snapshot)
  VALUES
    (p_contender_id, p_battle_id, p_lens_id, p_version_id, p_input_snapshot)
  ON CONFLICT (contender_id) DO UPDATE
    SET lens_id        = EXCLUDED.lens_id,
        version_id     = EXCLUDED.version_id,
        input_snapshot = EXCLUDED.input_snapshot
  RETURNING id, contender_id, battle_id, lens_id, version_id, assigned_at, input_snapshot;
$$;


ALTER FUNCTION "public"."fn_assign_lens_to_contender"("p_contender_id" "uuid", "p_battle_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid", "p_input_snapshot" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_assign_tool"("p_ai_lenser_id" "uuid", "p_tool_id" "uuid", "p_profile_id" "uuid" DEFAULT NULL::"uuid", "p_allowed" boolean DEFAULT true) RETURNS "agents"."tool_assignments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_row agents.tool_assignments;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.tool_assignments (ai_lenser_id, tool_id, profile_id, allowed)
  VALUES (p_ai_lenser_id, p_tool_id, p_profile_id, COALESCE(p_allowed, true))
  ON CONFLICT (ai_lenser_id, tool_id)
  DO UPDATE SET
    profile_id = EXCLUDED.profile_id,
    allowed    = EXCLUDED.allowed
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


