ALTER FUNCTION "public"."fn_byok_log_usage"("p_key_id" "uuid", "p_battle_id" "uuid", "p_model_id" "text", "p_token_count" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_log_usage"("p_key_id" "uuid", "p_battle_id" "uuid", "p_model_id" "text", "p_token_count" integer) IS 'BZ: Inserts a usage record into audit.byok_key_usage. Called fire-and-forget after each successful model call. SECURITY DEFINER; service_role only. Never exposes key material.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_rotation_due"() RETURNS SETOF "execution"."byok_keys"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
  SELECT *
  FROM execution.byok_keys
  WHERE revoked_at IS NULL
    AND last_rotated_at < now() - INTERVAL '90 days'
  ORDER BY last_rotated_at ASC;
$$;


ALTER FUNCTION "public"."fn_byok_rotation_due"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_rotation_due"() IS 'BZ: Returns byok_keys rows where last_rotated_at < now() - 90 days and not revoked. Used by the daily rotation-due cron and lf byok check-rotation CLI command.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_send_rotation_notifications"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'audit', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_key   execution.byok_keys%ROWTYPE;
  v_owner UUID;
  v_count INT := 0;
BEGIN
  FOR v_key IN (
    SELECT * FROM execution.byok_keys
    WHERE revoked_at    IS NULL
      AND last_rotated_at < now() - INTERVAL '90 days'
  ) LOOP
    -- Resolve owner: byok_keys → ai_lensers → profiles
    SELECT lp.id INTO v_owner
    FROM agents.ai_lensers al
    JOIN lensers.profiles lp ON lp.id = al.profile_id
    WHERE al.id = v_key.agent_id
    LIMIT 1;

    IF v_owner IS NOT NULL THEN
      PERFORM public.fn_send_notification(
        v_owner,
        'byok_rotation_due',
        jsonb_build_object(
          'key_id',          v_key.id,
          'provider',        v_key.provider,
          'agent_id',        v_key.agent_id,
          'last_rotated_at', v_key.last_rotated_at,
          'days_overdue',    EXTRACT(DAY FROM now() - v_key.last_rotated_at - INTERVAL '90 days')::int
        )
      );
      v_count := v_count + 1;
    END IF;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."fn_byok_send_rotation_notifications"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_send_rotation_notifications"() IS 'BZ: Sends byok_rotation_due notifications for all overdue keys. Called by daily pg_cron job. Returns count of notifications sent.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_actor_id       UUID;
  v_ai_lenser_id   UUID;
  v_key_row        execution.byok_keys%ROWTYPE;
  v_allowed_models TEXT[];
BEGIN
  -- Must be authenticated
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'authentication_required');
  END IF;

  -- Resolve the ai_lenser_id for this contender
  SELECT cem.ai_lenser_id INTO v_ai_lenser_id
  FROM battles.contender_entity_map cem
  WHERE cem.contender_id = p_contender_id
    AND cem.ai_lenser_id IS NOT NULL
  LIMIT 1;

  IF v_ai_lenser_id IS NULL THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'contender_has_no_agent');
  END IF;

  -- Caller must own this agent
  IF NOT EXISTS (
    SELECT 1
    FROM agents.ai_lensers al
    JOIN lensers.profiles lp ON lp.id = al.profile_id
    WHERE al.id = v_ai_lenser_id
      AND lp.id = v_actor_id
  ) THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'caller_does_not_own_agent');
  END IF;

  -- Get the first valid key for this agent (provider-agnostic validation)
  SELECT * INTO v_key_row
  FROM execution.byok_keys bk
  WHERE bk.agent_id  = v_ai_lenser_id
    AND bk.revoked_at IS NULL
    AND (bk.expires_at IS NULL OR bk.expires_at > now())
  ORDER BY bk.created_at DESC
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'no_valid_key');
  END IF;

  -- Check model allowlist against battle template
  SELECT bt.allowed_model_ids INTO v_allowed_models
  FROM battles.battles b
  JOIN battles.templates bt ON bt.id = b.template_id
  WHERE b.id = p_battle_id;

  IF v_allowed_models IS NOT NULL
    AND array_length(v_allowed_models, 1) > 0
    AND v_key_row.allowed_model_ids IS NOT NULL
  THEN
    -- Verify intersection is non-empty
    IF NOT EXISTS (
      SELECT 1
      FROM unnest(v_key_row.allowed_model_ids) AS km
      WHERE km = ANY(v_allowed_models)
    ) THEN
      RETURN jsonb_build_object(
        'valid', false,
        'reason', 'model_not_in_template_allowlist'
      );
    END IF;
  END IF;

  RETURN jsonb_build_object('valid', true, 'reason', null, 'key_id', v_key_row.id);
END;
$$;


ALTER FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") IS 'BZ: Validates that the contender in a battle has a usable BYOK key. Returns {valid, reason} JSON. SECURITY DEFINER; authenticated owner only.';



CREATE OR REPLACE FUNCTION "public"."fn_cancel_account_deletion_on_login"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_uid uuid;
  v_profile RECORD;
  v_event_type text;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('restored', false, 'reason', 'not_authenticated');
  END IF;

  SELECT id, user_id, status, deletion_deadline_at, deletion_requested_at
  INTO v_profile
  FROM lensers.profiles
  WHERE user_id = v_uid
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('restored', false, 'reason', 'no_profile');
  END IF;

  IF v_profile.status = 'pending_deletion'
     AND (v_profile.deletion_deadline_at IS NULL OR v_profile.deletion_deadline_at > now()) THEN
    UPDATE lensers.profiles
    SET status = 'active',
        deletion_requested_at = null,
        deletion_deadline_at = null,
        updated_at = now()
    WHERE id = v_profile.id;

    PERFORM lensers.log_account_lifecycle_event(
      v_profile.id,
      v_profile.user_id,
      'restored_from_pending_deletion',
      v_profile.status,
      'active'::lensers.lenser_status,
      'signin_restore',
      jsonb_build_object(
        'restored_before_deadline', true,
        'deletion_deadline_at', v_profile.deletion_deadline_at
      )
    );

    RETURN jsonb_build_object('restored', true, 'from_status', 'pending_deletion');
  END IF;

  IF (
    v_profile.status = 'deactivated' OR
    (v_profile.status = 'active' AND v_profile.deletion_requested_at IS NOT NULL)
  ) AND (
    v_profile.deletion_deadline_at IS NULL OR v_profile.deletion_deadline_at > now()
  ) THEN
    UPDATE lensers.profiles
    SET status = 'active',
        deletion_requested_at = null,
        deletion_deadline_at = null,
        updated_at = now()
    WHERE id = v_profile.id;

    v_event_type := CASE
      WHEN v_profile.status = 'active' THEN 'restored_from_pending_deletion'
      ELSE 'restored_from_deactivated'
    END;

    PERFORM lensers.log_account_lifecycle_event(
      v_profile.id,
      v_profile.user_id,
      v_event_type,
      v_profile.status,
      'active'::lensers.lenser_status,
      'signin_restore',
      jsonb_build_object(
        'restored_before_deadline', true,
        'deletion_deadline_at', v_profile.deletion_deadline_at,
        'cleared_stale_deletion_flags', v_profile.status = 'active'
      )
    );

    RETURN jsonb_build_object('restored', true, 'from_status', v_profile.status);
  END IF;

  RETURN jsonb_build_object('restored', false, 'reason', 'no_action_needed');
END;
$$;


ALTER FUNCTION "public"."fn_cancel_account_deletion_on_login"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_agent_run"("p_team_run_id" "uuid", "p_ai_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_human_lenser_id();
BEGIN
  UPDATE agents.team_runs
  SET status = 'cancelled'
  WHERE id = p_team_run_id
    AND ai_lenser_id = p_ai_lenser_id
    AND (
      EXISTS (
        SELECT 1 FROM agents.ownerships o
        WHERE o.ai_lenser_id = p_ai_lenser_id
          AND o.owner_lenser_id = v_lenser_id
          AND o.revoked_at IS NULL
      ) OR public.is_admin()
    );
END;
$$;


ALTER FUNCTION "public"."fn_cancel_agent_run"("p_team_run_id" "uuid", "p_ai_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_run"("p_team_run_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_run agents.team_runs;
BEGIN
  SELECT * INTO v_run
    FROM agents.team_runs
   WHERE id = p_team_run_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'team run not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_run.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  IF v_run.status IN ('completed','failed','cancelled') THEN
    RAISE EXCEPTION 'run already terminal' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.team_runs
     SET status       = 'cancelled',
         completed_at = now()
   WHERE id = p_team_run_id;

  IF v_run.workflow_run_id IS NOT NULL THEN
    UPDATE lenses.workflow_runs
       SET status       = 'cancelled',
           completed_at = COALESCE(completed_at, now())
     WHERE id = v_run.workflow_run_id
       AND status NOT IN ('completed','failed','cancelled');
  END IF;

  INSERT INTO agents.agent_run_events (
    team_run_id,
    event_type,
    payload,
    occurred_at
  ) VALUES (
    p_team_run_id,
    'run_cancelled',
    jsonb_build_object(
      'cancelled_by',     auth.uid(),
      'previous_status',  v_run.status
    ),
    now()
  );

  INSERT INTO agents.policy_evaluations (
    ai_lenser_id,
    team_run_id,
    evaluation_point,
    policy_type,
    verdict,
    reason,
    context,
    evaluated_at
  ) VALUES (
    v_run.ai_lenser_id,
    p_team_run_id,
    'pre_run',
    'kill_switch',
    'deny',
    'run cancelled by owner',
    jsonb_build_object('cancelled_by', auth.uid()),
    now()
  );
END;
$$;


ALTER FUNCTION "public"."fn_cancel_run"("p_team_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer DEFAULT 0) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_run            lenses.workflow_runs%ROWTYPE;
  v_projected      integer;
  v_pending        integer := GREATEST(COALESCE(p_pending_credits, 0), 0);
  v_cost_metadata  jsonb;
BEGIN
  SELECT * INTO v_run
  FROM lenses.workflow_runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  -- Never cancel already-terminal runs.
  IF v_run.status IN ('completed', 'failed', 'cancelled', 'timed_out') THEN
    RETURN FALSE;
  END IF;

  IF v_run.budget_credits IS NULL THEN
    RETURN FALSE;
  END IF;

  v_projected := COALESCE(v_run.spent_credits, 0) + v_pending;

  IF v_projected <= v_run.budget_credits THEN
    RETURN FALSE;
  END IF;

  v_cost_metadata := COALESCE(v_run.cost_metadata, '{}'::jsonb)
    || jsonb_build_object(
      'budgetCancellation', jsonb_build_object(
        'cancelledAt', now(),
        'budgetCredits', v_run.budget_credits,
        'spentCredits', v_run.spent_credits,
        'pendingCredits', v_pending,
        'projectedCredits', v_projected,
        'reason', 'budget_exceeded'
      )
    );

  UPDATE lenses.workflow_runs
  SET
    status       = 'cancelled',
    completed_at = now(),
    run_worker_id = NULL,
    cost_metadata = v_cost_metadata
  WHERE id = p_run_id;

  -- Cascade cancellation to any still-running node results so the timeline
  -- view does not keep spinners going forever.
  UPDATE lenses.workflow_node_results
  SET status       = 'cancelled',
      completed_at = now(),
      error_message = COALESCE(error_message, 'budget_exceeded')
  WHERE run_id = p_run_id
    AND status IN ('pending', 'awaiting_dependency', 'queued', 'running', 'streaming', 'retrying');

  -- Append an event so SSE clients see the cancellation immediately.
  INSERT INTO lenses.workflow_run_events (run_id, event_id, type, payload)
  SELECT
    p_run_id,
    COALESCE(MAX(e.event_id), 0) + 1,
    'run.cancelled',
    jsonb_build_object(
      'runId', p_run_id,
      'reason', 'budget_exceeded',
      'budgetCredits', v_run.budget_credits,
      'spentCredits', v_run.spent_credits,
      'pendingCredits', v_pending
    )
  FROM lenses.workflow_run_events e
  WHERE e.run_id = p_run_id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer) IS 'Phase 9 — cancels a run when spent_credits + pendingReservations exceed budget_credits. Cascades to node results and emits run.cancelled event. Invoked periodically by the worker heartbeat loop.';



CREATE OR REPLACE FUNCTION "public"."fn_check_and_upsert_aggregate"("p_recipient_id" "uuid", "p_actor_id" "uuid", "p_type" "text", "p_entity_id" "uuid", "p_window" interval) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_agg public.notification_aggregates;
BEGIN
  -- Look for an open window; lock the row to prevent parallel duplicates.
  SELECT *
  INTO   v_agg
  FROM   public.notification_aggregates
  WHERE  recipient_id      = p_recipient_id
    AND  notification_type = p_type
    AND  entity_id         = p_entity_id
    AND  window_end        > now()
  LIMIT  1
  FOR UPDATE SKIP LOCKED;

  IF FOUND THEN
    -- Within the window: append actor (if new) and suppress new notification.
    IF NOT (p_actor_id = ANY(v_agg.actor_ids)) THEN
      UPDATE public.notification_aggregates
      SET    actor_ids = array_append(actor_ids, p_actor_id)
      WHERE  id        = v_agg.id;
    END IF;
    RETURN false;
  END IF;

  -- No open window: create a new one and allow the notification.
  INSERT INTO public.notification_aggregates
    (recipient_id, notification_type, entity_id, window_start, window_end, actor_ids)
  VALUES
    (p_recipient_id, p_type, p_entity_id, now(), now() + p_window, ARRAY[p_actor_id]);

  RETURN true;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_check_and_upsert_aggregate failed: %', SQLERRM;
  RETURN true;  -- fail-open — allow the notification on error
END;
$$;


ALTER FUNCTION "public"."fn_check_and_upsert_aggregate"("p_recipient_id" "uuid", "p_actor_id" "uuid", "p_type" "text", "p_entity_id" "uuid", "p_window" interval) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_media_quality"("p_submission_id" "uuid") RETURNS "battles"."media_quality_results"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_submission  RECORD;
  v_template_id UUID;
  v_modality    TEXT;
  v_meta        JSONB;
  v_rule        RECORD;
  v_violations  TEXT[] := ARRAY[]::TEXT[];
  v_width       INT;
  v_height      INT;
  v_duration    INT;
  v_aspect      TEXT;
  v_size_mb     NUMERIC;
  v_result      battles.media_quality_results%ROWTYPE;
BEGIN
  SELECT s.*, b.template_id AS battle_template_id
    INTO v_submission
    FROM battles.submissions s
    JOIN battles.battles b ON b.id = s.battle_id
   WHERE s.id = p_submission_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'submission_not_found' USING ERRCODE = '42501';
  END IF;

  v_template_id := v_submission.battle_template_id;
  v_meta        := COALESCE(v_submission.metadata->'media', '{}'::jsonb);
  v_modality    := COALESCE(v_meta->>'modality', v_submission.metadata->>'output_modality');

  IF v_modality IS NULL OR v_modality NOT IN ('image','video','audio') THEN
    RAISE EXCEPTION 'unknown_modality: %', COALESCE(v_modality, '<null>')
      USING ERRCODE = '22023';
  END IF;

  -- Lookup the rule. Absence of a rule = pass (no floor declared).
  -- NOTE: a plpgsql record-typed `v_rule IS NOT NULL` is only true when EVERY
  -- column is non-NULL — wrong test for a row with optional fields. Use FOUND
  -- so we only enforce when a row was actually selected.
  SELECT * INTO v_rule
    FROM battles.media_quality_rules
   WHERE template_id = v_template_id
     AND modality    = v_modality;

  IF FOUND THEN
    v_width    := NULLIF(v_meta->>'width', '')::INT;
    v_height   := NULLIF(v_meta->>'height', '')::INT;
    v_duration := NULLIF(v_meta->>'duration_seconds', '')::INT;
    v_aspect   := v_meta->>'aspect_ratio';
    v_size_mb  := NULLIF(v_meta->>'size_mb', '')::NUMERIC;

    IF v_rule.min_width IS NOT NULL
       AND (v_width IS NULL OR v_width < v_rule.min_width) THEN
      v_violations := array_append(v_violations,
        format('min_width:%s<%s', COALESCE(v_width::text, 'null'), v_rule.min_width));
    END IF;
    IF v_rule.min_height IS NOT NULL
       AND (v_height IS NULL OR v_height < v_rule.min_height) THEN
      v_violations := array_append(v_violations,
        format('min_height:%s<%s', COALESCE(v_height::text, 'null'), v_rule.min_height));
    END IF;
    IF v_rule.max_duration_seconds IS NOT NULL
       AND v_duration IS NOT NULL
       AND v_duration > v_rule.max_duration_seconds THEN
      v_violations := array_append(v_violations,
        format('max_duration_seconds:%s>%s', v_duration, v_rule.max_duration_seconds));
    END IF;
    IF v_rule.required_aspect_ratio IS NOT NULL
       AND v_aspect IS DISTINCT FROM v_rule.required_aspect_ratio THEN
      v_violations := array_append(v_violations,
        format('aspect_ratio:%s!=%s', COALESCE(v_aspect, 'null'), v_rule.required_aspect_ratio));
    END IF;
    IF v_rule.max_file_size_mb IS NOT NULL
       AND v_size_mb IS NOT NULL
       AND v_size_mb > v_rule.max_file_size_mb THEN
      v_violations := array_append(v_violations,
        format('max_file_size_mb:%s>%s', v_size_mb, v_rule.max_file_size_mb));
    END IF;
  END IF;

  INSERT INTO battles.media_quality_results (
    submission_id, passed, violations, checked_at
  ) VALUES (
    p_submission_id,
    cardinality(v_violations) = 0,
    to_jsonb(v_violations),
    now()
  )
  ON CONFLICT (submission_id) DO UPDATE SET
    passed     = EXCLUDED.passed,
    violations = EXCLUDED.violations,
    checked_at = EXCLUDED.checked_at
  RETURNING * INTO v_result;

  RETURN v_result;
END $$;


ALTER FUNCTION "public"."fn_check_media_quality"("p_submission_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_vote_velocity"("p_voter_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'public'
    AS $$
DECLARE
  v_recent_count INT;
BEGIN
  SELECT COUNT(*)
    INTO v_recent_count
    FROM battles.votes
   WHERE voter_lenser_id = p_voter_id
     AND created_at >= now() - INTERVAL '60 seconds';

  IF v_recent_count >= 3 THEN
    RAISE EXCEPTION 'rate_limit_exceeded'
      USING ERRCODE = 'P0001',
            DETAIL  = 'You are voting too fast. Please wait before casting another vote.',
            HINT    = 'rate_limit_exceeded';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_check_vote_velocity"("p_voter_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_check_vote_velocity"("p_voter_id" "uuid") IS 'CA: Raises P0001 rate_limit_exceeded when voter has cast ≥3 votes in the last 60s.';



CREATE OR REPLACE FUNCTION "public"."fn_check_voter_eligibility"("p_battle_id" "uuid", "p_lenser_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_eligibility text;
  v_type        text;
  v_onboarding  text;
BEGIN
  SELECT voter_eligibility INTO v_eligibility
  FROM battles.battles
  WHERE id = p_battle_id;

  IF NOT FOUND THEN RETURN false; END IF;
  IF v_eligibility = 'open' THEN RETURN true; END IF;

  SELECT type, onboarding_step INTO v_type, v_onboarding
  FROM lensers.profiles
  WHERE id = p_lenser_id;

  IF NOT FOUND THEN RETURN false; END IF;

  IF    v_eligibility = 'human_only'      THEN RETURN v_type = 'human';
  ELSIF v_eligibility = 'ai_only'         THEN RETURN v_type = 'ai';
  ELSIF v_eligibility = 'verified_lenser' THEN RETURN v_onboarding = 'completed';
  END IF;

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."fn_check_voter_eligibility"("p_battle_id" "uuid", "p_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_webhook_signing_secret"() RETURNS TABLE("is_set" boolean, "length_bytes" integer, "strict_mode" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_secret text := current_setting('app.webhook_signing_secret', true);
  v_strict text := current_setting('app.webhook_strict_signing', true);
BEGIN
  is_set := v_secret IS NOT NULL AND length(v_secret) > 0;
  length_bytes := COALESCE(length(v_secret), 0);
  strict_mode := COALESCE(lower(v_strict) = 'true', false);
  RETURN NEXT;
END;
$$;


