    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'connectors'
    AS $$
BEGIN
    PERFORM connectors.fn_assert_scope(p_granted, p_required);
    RETURN jsonb_build_object('ok', true, 'required', p_required);
END
$$;


ALTER FUNCTION "public"."fn_connector_assert_scope"("p_required" "text", "p_granted" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_connector_create"("p_name" "text", "p_slug" "text", "p_description" "text", "p_scopes" "text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'connectors'
    AS $$
DECLARE
    v_workspace_id uuid := connectors.fn_active_workspace_id();
    v_user_id      uuid := auth.uid();
    v_connector_id uuid;
    v_token_raw    text;
    v_token_hash   text;
    v_token_prefix text;
BEGIN
    IF v_workspace_id IS NULL THEN
        RAISE EXCEPTION 'no active workspace for caller'
              USING ERRCODE = '42501';
    END IF;

    PERFORM connectors.fn_assert_known_scopes(p_scopes);
    IF cardinality(p_scopes) = 0 THEN
        RAISE EXCEPTION 'p_scopes must be non-empty' USING ERRCODE = '22023';
    END IF;

    INSERT INTO connectors.connectors (workspace_id, slug, name, description, created_by)
    VALUES (v_workspace_id, p_slug, p_name, NULLIF(p_description, ''), v_user_id)
    RETURNING id INTO v_connector_id;

    -- 32 random bytes → ~43-char base64url; "lf_" prefix marks origin.
    v_token_raw    := 'lf_' || encode(gen_random_bytes(32), 'base64');
    v_token_raw    := replace(replace(replace(v_token_raw, '+', '-'), '/', '_'), '=', '');
    v_token_hash   := connectors.fn_hash_token(v_token_raw);
    v_token_prefix := substring(v_token_raw FROM 1 FOR 11);

    INSERT INTO connectors.connector_tokens (connector_id, token_hash, token_prefix, scopes)
    VALUES (v_connector_id, v_token_hash, v_token_prefix, p_scopes);

    RETURN jsonb_build_object(
        'slug',          p_slug,
        'name',          p_name,
        'scopes',        p_scopes,
        'service_token', v_token_raw,
        'token_prefix',  v_token_prefix
    );
END
$$;


ALTER FUNCTION "public"."fn_connector_create"("p_name" "text", "p_slug" "text", "p_description" "text", "p_scopes" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_connector_get"("p_slug" "text") RETURNS TABLE("slug" "text", "name" "text", "description" "text", "scopes" "text"[], "is_active" boolean, "kind" "text", "created_at" timestamp with time zone, "last_used_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'connectors'
    AS $$
    SELECT c.slug,
           c.name,
           c.description,
           COALESCE(
               (SELECT t.scopes
                  FROM connectors.connector_tokens t
                 WHERE t.connector_id = c.id
                   AND t.revoked_at IS NULL
                 ORDER BY t.created_at DESC
                 LIMIT 1),
               ARRAY[]::text[]
           ) AS scopes,
           c.is_active,
           c.kind,
           c.created_at,
           c.last_used_at
      FROM connectors.connectors c
     WHERE c.workspace_id = connectors.fn_active_workspace_id()
       AND c.slug = p_slug
     LIMIT 1
$$;


ALTER FUNCTION "public"."fn_connector_get"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_connector_remove"("p_slug" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'connectors'
    AS $$
DECLARE
    v_connector_id uuid;
BEGIN
    SELECT c.id INTO v_connector_id
      FROM connectors.connectors c
     WHERE c.workspace_id = connectors.fn_active_workspace_id()
       AND c.slug = p_slug;

    IF v_connector_id IS NULL THEN
        RAISE EXCEPTION 'connector not found: %', p_slug USING ERRCODE = 'P0002';
    END IF;

    UPDATE connectors.connectors
       SET is_active = false
     WHERE id = v_connector_id;

    UPDATE connectors.connector_tokens
       SET revoked_at = now()
     WHERE connector_id = v_connector_id
       AND revoked_at IS NULL;
END
$$;


ALTER FUNCTION "public"."fn_connector_remove"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_connector_rotate"("p_slug" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'connectors'
    AS $$
DECLARE
    v_connector_id uuid;
    v_scopes       text[];
    v_token_raw    text;
    v_token_hash   text;
    v_token_prefix text;
BEGIN
    SELECT c.id INTO v_connector_id
      FROM connectors.connectors c
     WHERE c.workspace_id = connectors.fn_active_workspace_id()
       AND c.slug = p_slug
       AND c.is_active = true;

    IF v_connector_id IS NULL THEN
        RAISE EXCEPTION 'connector not found or inactive: %', p_slug USING ERRCODE = 'P0002';
    END IF;

    SELECT t.scopes INTO v_scopes
      FROM connectors.connector_tokens t
     WHERE t.connector_id = v_connector_id
       AND t.revoked_at IS NULL
     ORDER BY t.created_at DESC
     LIMIT 1;

    IF v_scopes IS NULL THEN
        RAISE EXCEPTION 'no active token to rotate for connector: %', p_slug USING ERRCODE = 'P0002';
    END IF;

    UPDATE connectors.connector_tokens
       SET revoked_at = now()
     WHERE connector_id = v_connector_id
       AND revoked_at IS NULL;

    v_token_raw    := 'lf_' || encode(gen_random_bytes(32), 'base64');
    v_token_raw    := replace(replace(replace(v_token_raw, '+', '-'), '/', '_'), '=', '');
    v_token_hash   := connectors.fn_hash_token(v_token_raw);
    v_token_prefix := substring(v_token_raw FROM 1 FOR 11);

    INSERT INTO connectors.connector_tokens (connector_id, token_hash, token_prefix, scopes)
    VALUES (v_connector_id, v_token_hash, v_token_prefix, v_scopes);

    RETURN jsonb_build_object(
        'slug',          p_slug,
        'service_token', v_token_raw,
        'token_prefix',  v_token_prefix
    );
END
$$;


ALTER FUNCTION "public"."fn_connector_rotate"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_connector_test"("p_slug" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'connectors'
    AS $$
DECLARE
    v_connector_id uuid;
    v_scopes       text[];
    v_started_at   timestamptz := clock_timestamp();
BEGIN
    SELECT c.id INTO v_connector_id
      FROM connectors.connectors c
     WHERE c.workspace_id = connectors.fn_active_workspace_id()
       AND c.slug = p_slug
       AND c.is_active = true;

    IF v_connector_id IS NULL THEN
        RETURN jsonb_build_object('ok', false, 'latency_ms', 0, 'scopes', '[]'::jsonb);
    END IF;

    SELECT t.scopes INTO v_scopes
      FROM connectors.connector_tokens t
     WHERE t.connector_id = v_connector_id
       AND t.revoked_at IS NULL
     ORDER BY t.created_at DESC
     LIMIT 1;

    UPDATE connectors.connectors
       SET last_used_at = now()
     WHERE id = v_connector_id;

    RETURN jsonb_build_object(
        'ok',         v_scopes IS NOT NULL,
        'latency_ms', EXTRACT(MILLISECOND FROM clock_timestamp() - v_started_at)::int,
        'scopes',     COALESCE(v_scopes, ARRAY[]::text[])
    );
END
$$;


ALTER FUNCTION "public"."fn_connector_test"("p_slug" "text") OWNER TO "postgres";


