CREATE OR REPLACE FUNCTION "public"."fn_get_gateway_device_health"() RETURNS TABLE("device_id" "uuid", "hostname" "text", "daemon_version" "text", "last_seen_at" timestamp with time zone, "approved_at" timestamp with time zone, "revoked_at" timestamp with time zone, "kill_switch" boolean, "created_at" timestamp with time zone, "pending_commands" bigint, "unacked_commands" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'extensions'
    AS $$
DECLARE
  v_uid UUID := auth.uid();
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
    SELECT v.device_id, v.hostname, v.daemon_version, v.last_seen_at,
           v.approved_at, v.revoked_at, v.kill_switch, v.created_at,
           v.pending_commands, v.unacked_commands
      FROM agents.v_gateway_device_health v
     WHERE v.owner_id = v_uid
     ORDER BY v.last_seen_at DESC NULLS LAST,
              v.created_at DESC;
END $$;


ALTER FUNCTION "public"."fn_get_gateway_device_health"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_global_lenserboard"("p_limit" integer DEFAULT 50) RETURNS TABLE("lenser_id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "total_wins" bigint, "total_battles" bigint, "win_rate" numeric, "total_votes_received" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers', 'reputation'
    AS $$
  SELECT
    lp.id                                                                  AS lenser_id,
    lp.handle,
    lp.display_name,
    lp.avatar_url,
    COUNT(c.id) FILTER (WHERE b.winner_contender_id = c.id)               AS total_wins,
    COUNT(c.id)                                                            AS total_battles,
    CASE WHEN COUNT(c.id) > 0
         THEN ROUND(
           COUNT(c.id) FILTER (WHERE b.winner_contender_id = c.id)::numeric
           / COUNT(c.id)::numeric, 4)
         ELSE 0::numeric
    END                                                                    AS win_rate,
    COALESCE(SUM(va.raw_vote_count), 0)                                    AS total_votes_received
  FROM lensers.profiles lp
  JOIN battles.contenders c ON c.contender_ref_id = lp.id
  JOIN battles.battles b
    ON b.id = c.battle_id AND b.status::text IN ('published', 'closed')
  LEFT JOIN battles.vote_aggregates va ON va.contender_id = c.id
  GROUP BY lp.id, lp.handle, lp.display_name, lp.avatar_url
  HAVING COUNT(c.id) > 0
  ORDER BY total_wins DESC, total_battles DESC
  LIMIT LEAST(GREATEST(COALESCE(p_limit, 50), 1), 200);
$$;


ALTER FUNCTION "public"."fn_get_global_lenserboard"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_global_messages"("p_battle_id" "uuid", "p_limit" integer DEFAULT 50, "p_before_ts" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "sender_id" "uuid", "sender_handle" "text", "sender_role" "text", "body" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    id,
    battle_id,
    sender_id,
    sender_handle,
    sender_role,
    body,
    created_at
  FROM battles.global_messages
  WHERE battle_id = p_battle_id
    AND (
      p_before_ts IS NULL
      OR (created_at, id) < (p_before_ts, p_before_id)
    )
  ORDER BY created_at DESC, id DESC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."fn_get_global_messages"("p_battle_id" "uuid", "p_limit" integer, "p_before_ts" timestamp with time zone, "p_before_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_head_to_head"("p_lenser_a" "uuid", "p_lenser_b" "uuid") RETURNS TABLE("total_battles" bigint, "a_wins" bigint, "b_wins" bigint, "draws" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  WITH shared_battles AS (
    -- Battles where both lensers participated
    SELECT ca.battle_id
    FROM battles.contenders ca
    JOIN battles.contenders cb ON cb.battle_id = ca.battle_id
      AND cb.contender_ref_id = p_lenser_b
    WHERE ca.contender_ref_id = p_lenser_a
  ),
  outcomes AS (
    SELECT
      b.id AS battle_id,
      MAX(CASE WHEN c.contender_ref_id = p_lenser_a AND b.winner_contender_id = c.id THEN 1 ELSE 0 END) AS a_won,
      MAX(CASE WHEN c.contender_ref_id = p_lenser_b AND b.winner_contender_id = c.id THEN 1 ELSE 0 END) AS b_won
    FROM shared_battles sb
    JOIN battles.battles b ON b.id = sb.battle_id
    JOIN battles.contenders c ON c.battle_id = b.id
      AND c.contender_ref_id IN (p_lenser_a, p_lenser_b)
    WHERE b.status IN ('closed', 'published')
    GROUP BY b.id
  )
  SELECT
    COUNT(*)                               AS total_battles,
    SUM(CASE WHEN a_won = 1 AND b_won = 0 THEN 1 ELSE 0 END) AS a_wins,
    SUM(CASE WHEN b_won = 1 AND a_won = 0 THEN 1 ELSE 0 END) AS b_wins,
    SUM(CASE WHEN a_won = b_won           THEN 1 ELSE 0 END) AS draws
  FROM outcomes
$$;


ALTER FUNCTION "public"."fn_get_head_to_head"("p_lenser_a" "uuid", "p_lenser_b" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_head_to_head"("p_lenser_a" "uuid", "p_lenser_b" "uuid") IS 'Returns aggregate win/loss/draw stats for two lensers across all battles where both participated. SECURITY DEFINER — caller visibility is public.';



CREATE OR REPLACE FUNCTION "public"."fn_get_human_activity_feed"("p_human_lenser_id" "uuid", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS TABLE("occurred_at" timestamp with time zone, "kind" "text", "ai_lenser_id" "uuid", "ai_lenser_handle" "text", "ai_lenser_name" "text", "title" "text", "status" "text", "team_run_id" "uuid", "workflow_id" "uuid", "schedule_id" "uuid", "action_type" "text", "payload" "jsonb")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers', 'lenses'
    AS $$
DECLARE
  v_caller uuid;
  v_safe_limit integer := COALESCE(p_limit, 50);
  v_safe_offset integer := COALESCE(p_offset, 0);
BEGIN
  v_caller := lensers.get_auth_human_lenser_id();
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'Authentication required.' USING ERRCODE = '42501';
  END IF;

  IF v_caller <> p_human_lenser_id THEN
    RAISE EXCEPTION 'Forbidden: cannot read another human Lenser''s activity feed.'
      USING ERRCODE = '42501';
  END IF;

  IF v_safe_limit < 1 THEN v_safe_limit := 1; END IF;
  IF v_safe_limit > 200 THEN v_safe_limit := 200; END IF;
  IF v_safe_offset < 0 THEN v_safe_offset := 0; END IF;

  RETURN QUERY
  WITH owned_agents AS (
    SELECT o.ai_lenser_id, p.handle, p.display_name
    FROM agents.ownerships o
    JOIN agents.ai_lensers al ON al.id = o.ai_lenser_id
    JOIN lensers.profiles p ON p.id = al.profile_id
    WHERE o.owner_lenser_id = v_caller
      AND o.role IN ('owner', 'co_owner')
      AND o.revoked_at IS NULL
  ),
  approval_items AS (
    SELECT
      tr.created_at AS occurred_at,
      'approval_pending'::text AS kind,
      tr.ai_lenser_id,
      oa.handle AS ai_lenser_handle,
      oa.display_name AS ai_lenser_name,
      COALESCE(w.title, 'Untitled workflow') AS title,
      'pending'::text AS status,
      tr.id AS team_run_id,
      tr.workflow_id,
      NULL::uuid AS schedule_id,
      NULL::text AS action_type,
      jsonb_build_object(
        'gate_kind', tr.metadata->>'gate_kind',
        'requested_action', tr.metadata->>'requested_action',
        'requester_agent_id', tr.metadata->>'requester_agent_id'
      ) AS payload
    FROM agents.team_runs tr
    JOIN owned_agents oa ON oa.ai_lenser_id = tr.ai_lenser_id
    LEFT JOIN lenses.workflows w ON w.id = tr.workflow_id
    WHERE tr.approval_status = 'pending'
  ),
  run_items AS (
    SELECT
      COALESCE(tr.completed_at, tr.started_at, tr.created_at) AS occurred_at,
      'team_run'::text AS kind,
      tr.ai_lenser_id,
      oa.handle AS ai_lenser_handle,
      oa.display_name AS ai_lenser_name,
      COALESCE(w.title, 'Untitled workflow') AS title,
      tr.status,
      tr.id AS team_run_id,
      tr.workflow_id,
      NULL::uuid AS schedule_id,
      NULL::text AS action_type,
      jsonb_build_object(
        'approval_status', tr.approval_status,
        'started_at', tr.started_at,
        'completed_at', tr.completed_at
      ) AS payload
    FROM agents.team_runs tr
    JOIN owned_agents oa ON oa.ai_lenser_id = tr.ai_lenser_id
    LEFT JOIN lenses.workflows w ON w.id = tr.workflow_id
    WHERE tr.approval_status <> 'pending'
  ),
  schedule_items AS (
    SELECT
      COALESCE(s.last_run_at, s.created_at) AS occurred_at,
      'schedule_dispatch'::text AS kind,
      al.id AS ai_lenser_id,
      oa.handle AS ai_lenser_handle,
      oa.display_name AS ai_lenser_name,
      COALESCE(w.title, 'Untitled workflow') AS title,
      COALESCE(s.last_dispatch_status, 'never_dispatched') AS status,
      NULL::uuid AS team_run_id,
      s.workflow_id,
      s.id AS schedule_id,
      NULL::text AS action_type,
      jsonb_build_object(
        'cron_expr', s.cron_expr,
        'timezone', s.timezone,
        'next_run_at', s.next_run_at,
        'last_error_message', s.last_error_message,
        'assignee_type', s.assignee_type,
        'assignee_id', s.assignee_id
      ) AS payload
    FROM lenses.workflow_schedules s
    JOIN lenses.workflows w ON w.id = s.workflow_id
    -- Schedules are bound to a workflow whose lenser_id is the AI workspace
    -- profile id when assignee_type='agent'; otherwise we resolve via the
    -- assignee_id column.
    JOIN agents.ai_lensers al
      ON al.id = COALESCE(
           CASE WHEN s.assignee_type = 'agent' THEN s.assignee_id END,
           (SELECT id FROM agents.ai_lensers ail WHERE ail.profile_id = w.lenser_id)
         )
    JOIN owned_agents oa ON oa.ai_lenser_id = al.id
  ),
  action_items AS (
    SELECT
      a.occurred_at,
      'agent_action'::text AS kind,
      a.ai_lenser_id,
      oa.handle AS ai_lenser_handle,
      oa.display_name AS ai_lenser_name,
      a.action_type AS title,
      a.result AS status,
      NULL::uuid AS team_run_id,
      NULL::uuid AS workflow_id,
      NULL::uuid AS schedule_id,
      a.action_type,
      a.metadata AS payload
    FROM agents.action_logs a
    JOIN owned_agents oa ON oa.ai_lenser_id = a.ai_lenser_id
  ),
  combined AS (
    SELECT * FROM approval_items
    UNION ALL
    SELECT * FROM run_items
    UNION ALL
    SELECT * FROM schedule_items
    UNION ALL
    SELECT * FROM action_items
  )
  SELECT *
  FROM combined
  ORDER BY occurred_at DESC NULLS LAST
  LIMIT v_safe_limit OFFSET v_safe_offset;
END;
$$;


ALTER FUNCTION "public"."fn_get_human_activity_feed"("p_human_lenser_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_human_activity_feed"("p_human_lenser_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'Cross-agent activity feed for the calling human Lenser. Aggregates pending approvals, recent team runs, schedule dispatches, and agent actions across every owned AI lenser. Caller must equal p_human_lenser_id.';



