CREATE OR REPLACE FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text" DEFAULT 'xp'::"text", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "xp"."v_leaderboard"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'reputation', 'lensers', 'public'
    AS $$
BEGIN
  IF p_order_by = 'elo' THEN
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY elo_score DESC, total_xp DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  ELSE
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY total_xp DESC, elo_score DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  END IF;
END;
$$;


