        SELECT o.ai_lenser_id FROM agents.ownerships o
        WHERE o.owner_lenser_id = lensers.get_auth_lenser_id()
          AND o.revoked_at IS NULL
      )
      OR public.fn_is_super_admin()
    )
  LIMIT 1;
$$;


