CREATE OR REPLACE FUNCTION "public"."fn_get_thread_replies_page"("p_thread_id" "uuid", "p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "thread_id" "uuid", "parent_reply_id" "uuid", "lenser_id" "uuid", "content" "text", "content_html" "text", "reaction_totals" "jsonb", "created_at" timestamp with time zone, "author_profile" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'content', 'lensers', 'auth'
    AS $$
  WITH RECURSIVE root_page AS (
    -- Select only top-level (root) replies for this page, respecting RLS via SECURITY INVOKER
    SELECT r.id
    FROM content.thread_replies r
    WHERE r.thread_id     = p_thread_id
      AND r.parent_reply_id IS NULL
      AND r.status        = 'published'
      AND r.deleted_at    IS NULL
    ORDER BY r.created_at ASC
    LIMIT  LEAST(p_limit, 50)
    OFFSET p_offset
  ),
  descendants AS (
    -- Seed: the root replies for this page
    SELECT r.id, r.parent_reply_id
    FROM content.thread_replies r
    WHERE r.id IN (SELECT id FROM root_page)
    UNION ALL
    -- Recurse: children of already-selected replies
    SELECT r.id, r.parent_reply_id
    FROM content.thread_replies r
    INNER JOIN descendants d ON r.parent_reply_id = d.id
    WHERE r.status     = 'published'
      AND r.deleted_at IS NULL
  )
  SELECT
    v.id,
    v.thread_id,
    v.parent_reply_id,
    v.lenser_id,
    v.content,
    v.content_html,
    v.reaction_totals,
    v.created_at,
    v.author_profile
  FROM public.vw_content_thread_replies_public v
  WHERE v.id IN (SELECT id FROM descendants)
  ORDER BY v.created_at ASC;
$$;


ALTER FUNCTION "public"."fn_get_thread_replies_page"("p_thread_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_thread_replies_page"("p_thread_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'Paginated thread replies. Paginates by root reply count (LIMIT/OFFSET on root-level entries), then recursively fetches all descendants of the selected roots. Hard cap: 50 root replies per call. Uses SECURITY INVOKER so RLS is enforced.';



CREATE OR REPLACE FUNCTION "public"."fn_get_thread_replies_private"("p_thread_id" "uuid", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "thread_id" "uuid", "parent_reply_id" "uuid", "lenser_id" "uuid", "content" "text", "created_at" timestamp with time zone, "deleted_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'content', 'lensers'
    AS $$
  SELECT r.id, r.thread_id, r.parent_reply_id, r.lenser_id,
         r.content, r.created_at, r.deleted_at
  FROM content.thread_replies r
  JOIN content.threads t ON t.id = r.thread_id
  WHERE r.thread_id = p_thread_id
    AND t.lenser_id = lensers.get_auth_lenser_id()
  ORDER BY r.created_at ASC
  LIMIT  LEAST(GREATEST(COALESCE(p_limit, 50), 1), 200)
  OFFSET GREATEST(COALESCE(p_offset, 0), 0);
$$;


ALTER FUNCTION "public"."fn_get_thread_replies_private"("p_thread_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_thread_replies_private"("p_thread_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'Security wrapper: paginated replies for a private thread owned by the current user.';



CREATE OR REPLACE FUNCTION "public"."fn_get_tool_invocation_rollup"("p_ai_lenser_id" "uuid", "p_days" integer DEFAULT 7) RETURNS TABLE("workflow_id" "uuid", "workflow_title" "text", "tool_name" "text", "total_invocations" bigint, "approved_count" bigint, "rejected_count" bigint, "last_invoked_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public', 'platform', 'lenses', 'agents'
    AS $$
DECLARE
  v_window int := GREATEST(LEAST(COALESCE(p_days, 7), 90), 1);
BEGIN
  IF p_ai_lenser_id IS NULL THEN
    RAISE EXCEPTION 'ai_lenser_id required' USING ERRCODE = '22023';
  END IF;

  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not_owner_of_ai_lenser' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT
    wr.workflow_id,
    w.title                                            AS workflow_title,
    til.tool_name,
    count(*)::bigint                                   AS total_invocations,
    count(*) FILTER (
      WHERE til.approval_status IN ('approved', 'auto_approved')
    )::bigint                                          AS approved_count,
    count(*) FILTER (
      WHERE til.approval_status = 'rejected'
    )::bigint                                          AS rejected_count,
    max(til.invoked_at)                                AS last_invoked_at
  FROM   platform.tool_invocation_logs til
  LEFT JOIN lenses.workflow_runs wr ON wr.id = til.run_id
  LEFT JOIN lenses.workflows     w  ON w.id  = wr.workflow_id
  WHERE  til.ai_lenser_id = p_ai_lenser_id
    AND  til.invoked_at >= now() - (v_window::text || ' days')::interval
  GROUP  BY wr.workflow_id, w.title, til.tool_name
  ORDER  BY total_invocations DESC, last_invoked_at DESC;
END;
$$;


ALTER FUNCTION "public"."fn_get_tool_invocation_rollup"("p_ai_lenser_id" "uuid", "p_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_tool_invocation_rollup"("p_ai_lenser_id" "uuid", "p_days" integer) IS 'Phase Q4: per-(workflow,tool_name) rollup of platform.tool_invocation_logs over the last p_days (default 7, hard-capped to [1,90]). SECURITY INVOKER preserves underlying RLS; explicit can_manage_ai_lenser guard prevents cross-owner enumeration via the workflow JOIN.';



CREATE OR REPLACE FUNCTION "public"."fn_get_tournament_bracket"("p_tournament_id" "uuid") RETURNS TABLE("round_number" integer, "round_status" "text", "match_id" "uuid", "battle_id" "uuid", "battle_slug" "text", "contender_a_lenser_id" "uuid", "contender_a_handle" "text", "contender_a_avatar_url" "text", "contender_b_lenser_id" "uuid", "contender_b_handle" "text", "contender_b_avatar_url" "text", "winner_lenser_id" "uuid", "winner_handle" "text", "winner_avatar_url" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
  SELECT
    tr.round_number,
    tr.status::TEXT          AS round_status,
    tm.id                    AS match_id,
    tm.battle_id,
    b.slug                   AS battle_slug,
    tca.lenser_id            AS contender_a_lenser_id,
    pa.handle                AS contender_a_handle,
    pa.avatar_url            AS contender_a_avatar_url,
    tcb.lenser_id            AS contender_b_lenser_id,
    pb.handle                AS contender_b_handle,
    pb.avatar_url            AS contender_b_avatar_url,
    tcw.lenser_id            AS winner_lenser_id,
    pw.handle                AS winner_handle,
    pw.avatar_url            AS winner_avatar_url
  FROM battles.tournament_rounds tr
  JOIN  battles.tournament_matches tm    ON tm.round_id = tr.id
  LEFT JOIN battles.battles b            ON b.id = tm.battle_id
  LEFT JOIN battles.tournament_contenders tca ON tca.id = tm.contender_a_id
  LEFT JOIN battles.tournament_contenders tcb ON tcb.id = tm.contender_b_id
  LEFT JOIN battles.tournament_contenders tcw ON tcw.id = tm.winner_tournament_contender_id
  LEFT JOIN lensers.profiles pa ON pa.id = tca.lenser_id
  LEFT JOIN lensers.profiles pb ON pb.id = tcb.lenser_id
  LEFT JOIN lensers.profiles pw ON pw.id = tcw.lenser_id
  WHERE tr.tournament_id = p_tournament_id
  ORDER BY tr.round_number, tm.created_at;
$$;


ALTER FUNCTION "public"."fn_get_tournament_bracket"("p_tournament_id" "uuid") OWNER TO "postgres";


