    r.triggered_by,
    r.status,
    r.context_inputs,
    r.started_at,
    r.completed_at,
    r.created_at
  FROM lenses.workflow_runs r
  JOIN lenses.workflows w ON w.id = r.workflow_id
  WHERE r.id = p_run_id
    AND (
      w.visibility = 'public'
      OR w.lenser_id = lensers.get_auth_lenser_id()
