CREATE OR REPLACE FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") RETURNS TABLE("run_id" "uuid", "workflow_id" "uuid", "status" "text", "active_node_id" "uuid", "pending_count" integer, "waiting_count" integer, "in_flight_count" integer, "executed_count" integer, "failed_count" integer, "is_running" boolean, "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "parent_run_id" "uuid", "recursion_depth" integer, "node_results" "jsonb", "upstream_count" integer, "downstream_count" integer)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
  WITH run AS (
    SELECT *
    FROM lenses.workflow_runs r
    WHERE r.id = p_run_id
      AND EXISTS (
        SELECT 1
        FROM lenses.workflows w
        WHERE w.id = r.workflow_id
          AND (
            r.triggered_by = lensers.get_auth_lenser_id()
            OR w.visibility::text = 'public'
          )
      )
  ),
  results AS (
    SELECT
      nr.*,
      n.label    AS node_label,
      n.ordinal  AS node_ordinal
    FROM lenses.workflow_node_results nr
    LEFT JOIN lenses.workflow_nodes n ON n.id = nr.node_id
    WHERE nr.run_id = p_run_id
  ),
  agg AS (
    SELECT
      COUNT(*) FILTER (WHERE results.status = 'pending')                                                     AS pending_count,
      COUNT(*) FILTER (WHERE results.status IN ('awaiting_dependency', 'queued'))                            AS waiting_count,
      COUNT(*) FILTER (WHERE results.status IN ('running', 'streaming', 'retrying'))                         AS in_flight_count,
      COUNT(*) FILTER (WHERE results.status IN ('completed', 'skipped'))                                     AS executed_count,
      COUNT(*) FILTER (WHERE results.status IN ('failed', 'timed_out', 'blocked', 'invalidated', 'cancelled')) AS failed_count
    FROM results
  ),
  prov AS (
    SELECT
      COUNT(*) FILTER (WHERE p.target_run_id = p_run_id) AS upstream_count,
      COUNT(*) FILTER (WHERE p.source_run_id = p_run_id) AS downstream_count
    FROM lenses.workflow_run_provenance p
    WHERE p.target_run_id = p_run_id OR p.source_run_id = p_run_id
  ),
  ordered_results AS (
    SELECT jsonb_agg(
      jsonb_build_object(
        'id',              results.id,
        'node_id',         results.node_id,
        'node_label',      results.node_label,
        'node_ordinal',    results.node_ordinal,
        'status',          results.status,
        'waiting_reason',  results.waiting_reason,
        'output_data',     results.output_data,
        'error_message',   results.error_message,
        'retry_count',     results.retry_count,
        'duration_ms',     results.duration_ms,
        'ttfb_ms',         results.ttfb_ms,
        'started_at',      results.started_at,
        'completed_at',    results.completed_at
      )
      ORDER BY results.node_ordinal NULLS LAST, results.id
    ) AS data
    FROM results
  )
  SELECT
    run.id,
    run.workflow_id,
    run.status::text,
    run.active_node_id,
    COALESCE(agg.pending_count, 0)::int,
    COALESCE(agg.waiting_count, 0)::int,
    COALESCE(agg.in_flight_count, 0)::int,
    COALESCE(agg.executed_count, 0)::int,
    COALESCE(agg.failed_count, 0)::int,
    (run.status NOT IN ('completed', 'failed', 'cancelled', 'timed_out')) AS is_running,
    run.started_at,
    run.completed_at,
    run.parent_run_id,
    run.recursion_depth,
    COALESCE(ordered_results.data, '[]'::jsonb),
    COALESCE(prov.upstream_count, 0)::int,
    COALESCE(prov.downstream_count, 0)::int
  FROM run
  CROSS JOIN agg
  CROSS JOIN prov
  CROSS JOIN ordered_results;
$$;


ALTER FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") IS 'N8N-style canonical run projection. One round-trip returns active node, waiting/executed counts, ordered node results, and provenance edge counts. Drives the workflow execution inspector.';



CREATE OR REPLACE FUNCTION "public"."fn_get_workflow_schedule_history"("p_schedule_id" "uuid") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "status" "text", "scheduled_for" timestamp with time zone, "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
  SELECT
    wr.id,
    wr.workflow_id,
    wr.status,
    wr.scheduled_for,
    wr.started_at,
    wr.completed_at,
    wr.created_at
  FROM lenses.workflow_runs wr
  JOIN lenses.workflow_schedules ws ON ws.id = wr.schedule_id
  JOIN lenses.workflows w ON w.id = wr.workflow_id
  WHERE wr.schedule_id = p_schedule_id
    AND wr.scheduled_for IS NOT NULL
    AND w.lenser_id = lensers.get_auth_lenser_id()
  ORDER BY wr.scheduled_for DESC
  LIMIT 50;
$$;


