COMMENT ON FUNCTION "public"."fn_heartbeat_workflow_run"("p_run_id" "uuid", "p_worker_id" "text") IS 'Lightweight keep-alive pinged by the execution worker every HEARTBEAT_MS. Used by fn_claim_stale_workflow_run (Phase 7) to detect stalled runs. Only writes while the run is in a non-terminal state.';



CREATE OR REPLACE FUNCTION "public"."fn_human_fleet_logs"("p_human_lenser_id" "uuid", "p_run_id" "uuid" DEFAULT NULL::"uuid", "p_event_type" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS SETOF "agents"."v_human_fleet_logs"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'agents'
    AS $$
  SELECT *
    FROM agents.v_human_fleet_logs
   WHERE human_lenser_id = p_human_lenser_id
     AND human_lenser_id = auth.uid()
     AND (p_run_id     IS NULL OR team_run_id = p_run_id)
     AND (p_event_type IS NULL OR event_type   = p_event_type)
   ORDER BY occurred_at DESC
   LIMIT GREATEST(0, LEAST(COALESCE(p_limit, 100), 500))
  OFFSET GREATEST(0, COALESCE(p_offset, 0));
$$;


ALTER FUNCTION "public"."fn_human_fleet_logs"("p_human_lenser_id" "uuid", "p_run_id" "uuid", "p_event_type" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_human_fleet_runs"("p_human_lenser_id" "uuid", "p_status" "text" DEFAULT NULL::"text", "p_agent_id" "uuid" DEFAULT NULL::"uuid", "p_since" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "agents"."v_human_fleet_runs"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'agents'
    AS $$
  SELECT *
    FROM agents.v_human_fleet_runs
   WHERE human_lenser_id = p_human_lenser_id
     AND human_lenser_id = auth.uid()
     AND (p_status   IS NULL OR status     = p_status)
     AND (p_agent_id IS NULL OR ai_lenser_id = p_agent_id)
     AND (p_since    IS NULL OR created_at >= p_since)
   ORDER BY created_at DESC
   LIMIT GREATEST(0, LEAST(COALESCE(p_limit, 50), 200))
  OFFSET GREATEST(0, COALESCE(p_offset, 0));
$$;


ALTER FUNCTION "public"."fn_human_fleet_runs"("p_human_lenser_id" "uuid", "p_status" "text", "p_agent_id" "uuid", "p_since" timestamp with time zone, "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_insert_notification"("p_lenser_id" "uuid", "p_type" "text", "p_title" "text", "p_body" "text" DEFAULT NULL::"text", "p_action_url" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM lensers.profiles WHERE id = p_lenser_id) THEN
    RETURN NULL;
  END IF;

  INSERT INTO public.notifications (lenser_id, type, title, body, action_url, metadata)
  VALUES (p_lenser_id, p_type, p_title, p_body, p_action_url, p_metadata)
  RETURNING id INTO v_id;

  RETURN v_id;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_insert_notification failed for lenser=% type=%: %',
    p_lenser_id, p_type, SQLERRM;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."fn_insert_notification"("p_lenser_id" "uuid", "p_type" "text", "p_title" "text", "p_body" "text", "p_action_url" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_insert_notification"("p_lenser_id" "uuid", "p_type" "text", "p_title" "text", "p_body" "text" DEFAULT NULL::"text", "p_action_url" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  -- Recipient must exist
  IF NOT EXISTS (SELECT 1 FROM lensers.profiles WHERE id = p_lenser_id) THEN
    RETURN NULL;
  END IF;

  -- Privacy gate: only runs when an actor is identified
  IF p_actor_id IS NOT NULL THEN
    IF NOT public.fn_should_send_notification(p_lenser_id, p_actor_id, p_type) THEN
      RETURN NULL;
    END IF;
  END IF;

  INSERT INTO public.notifications (lenser_id, type, title, body, action_url, metadata)
  VALUES (p_lenser_id, p_type, p_title, p_body, p_action_url, p_metadata)
  RETURNING id INTO v_id;

  RETURN v_id;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_insert_notification failed for lenser=% type=%: %',
    p_lenser_id, p_type, SQLERRM;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."fn_insert_notification"("p_lenser_id" "uuid", "p_type" "text", "p_title" "text", "p_body" "text", "p_action_url" "text", "p_metadata" "jsonb", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_integrity_probe_elo_log"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'reputation', 'pg_catalog'
    AS $$
DECLARE
  v_table_exists boolean;
  v_has_pk_on_battle_id boolean;
BEGIN
  SELECT EXISTS (
    SELECT 1 FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'reputation' AND c.relname = 'elo_battle_log'
  ) INTO v_table_exists;

  SELECT EXISTS (
    SELECT 1 FROM pg_constraint con
    JOIN pg_class c ON c.oid = con.conrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    JOIN pg_attribute a ON a.attrelid = c.oid AND a.attnum = ANY (con.conkey)
    WHERE n.nspname = 'reputation'
      AND c.relname = 'elo_battle_log'
      AND con.contype = 'p'
      AND a.attname = 'battle_id'
  ) INTO v_has_pk_on_battle_id;

  RETURN jsonb_build_object(
    'table_exists', v_table_exists,
    'has_pk_on_battle_id', v_has_pk_on_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_integrity_probe_elo_log"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_integrity_probe_elo_log"() IS 'Phase P automation. Reflects the existence + PK shape of reputation.elo_battle_log so the staging integrity script can verify idempotency infrastructure. service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_integrity_probe_moderation_override"("p_target_entity_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'audit'
    AS $$
DECLARE
  v_decision_id uuid;
  v_audit_row_present boolean;
BEGIN
  -- Insert a synthetic flagged decision (AI-moderated, no human moderator).
  INSERT INTO audit.moderation_decisions
    (target_entity_schema, target_entity_table, target_entity_id,
     decision_type, reason, is_ai_moderated, ai_confidence)
  VALUES
    ('battles', 'battles', p_target_entity_id,
     'flagged', '__integrity_probe_synthetic_flag', true, 0.95)
  RETURNING id INTO v_decision_id;

  -- Verify the row landed.
  SELECT EXISTS (
    SELECT 1 FROM audit.moderation_decisions
    WHERE id = v_decision_id AND decision_type = 'flagged'
  ) INTO v_audit_row_present;

  -- Cleanup so probe rows don't accumulate.
  DELETE FROM audit.moderation_decisions WHERE id = v_decision_id;

  RETURN jsonb_build_object(
    'decision_id', v_decision_id,
    'audit_row_present', v_audit_row_present,
    'cleaned_up', true
  );
END;
$$;


ALTER FUNCTION "public"."fn_integrity_probe_moderation_override"("p_target_entity_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_integrity_probe_moderation_override"("p_target_entity_id" "uuid") IS 'Phase P automation. Inserts a synthetic flagged moderation_decisions row, verifies it landed, then cleans up. service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_integrity_probe_moderation_webhook"("p_target_url" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'audit'
    AS $$
DECLARE
  v_probe_id text := '__integrity_probe_' || gen_random_uuid()::text;
  v_decision_id uuid;
  v_outbox_id uuid;
  v_prior_url text := current_setting('app.moderation_webhook_url', true);
BEGIN
  -- Temporarily point the webhook URL at the listener.
  PERFORM set_config('app.moderation_webhook_url', p_target_url, true);

  -- Insert a flagged decision; the AFTER INSERT trigger enqueues into outbox.
  INSERT INTO audit.moderation_decisions
    (target_entity_schema, target_entity_table, target_entity_id,
     decision_type, reason, is_ai_moderated, ai_confidence)
  VALUES
    ('battles', 'battles', gen_random_uuid(),
     'flagged', v_probe_id, true, 0.99)
  RETURNING id INTO v_decision_id;

  -- Restore prior URL setting for the rest of the session.
  PERFORM set_config('app.moderation_webhook_url', COALESCE(v_prior_url, ''), true);

  -- Force-run the dispatcher so the listener gets the POST without waiting
  -- for the cron tick. dispatch_webhook_outbox is idempotent.
  PERFORM audit.fn_dispatch_webhook_outbox(50);

  -- Cleanup the synthetic decision.
  DELETE FROM audit.moderation_decisions WHERE id = v_decision_id;

  RETURN jsonb_build_object(
    'probe_id', v_probe_id,
    'decision_id', v_decision_id,
    'enqueued', true
  );
END;
$$;


ALTER FUNCTION "public"."fn_integrity_probe_moderation_webhook"("p_target_url" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_integrity_probe_moderation_webhook"("p_target_url" "text") IS 'Phase P automation. Inserts a synthetic flagged decision with the listener URL set transiently, force-dispatches the outbox, cleans up. service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_invite_battle_contender"("p_battle_id" "uuid", "p_slot" "text", "p_contender_type" "text", "p_contender_ref_id" "uuid", "p_display_name" "text") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "slot" "text", "contender_type" "text", "display_name" "text", "contender_ref_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM battles.battles
    WHERE id = p_battle_id AND creator_lenser_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'invite_contender_forbidden' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  INSERT INTO battles.contenders (
    battle_id, slot, contender_type, contender_ref_id, display_name,
    entry_mode, contender_status
  ) VALUES (
    p_battle_id, p_slot, p_contender_type, p_contender_ref_id, p_display_name,
    'invited', 'pending'
  )
  RETURNING id, battle_id, slot, contender_type, display_name, contender_ref_id;
END;
$$;


ALTER FUNCTION "public"."fn_invite_battle_contender"("p_battle_id" "uuid", "p_slot" "text", "p_contender_type" "text", "p_contender_ref_id" "uuid", "p_display_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_invoke_tool"("p_team_run_id" "uuid", "p_tool_id" "uuid", "p_ai_lenser_id" "uuid", "p_input" "jsonb", "p_agent_run_step_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_tool          agents.tools_registry;
  v_assignment    agents.tool_assignments;
  v_profile       agents.tool_profiles;
  v_requires      boolean := false;
  v_appr_status   text;
  v_status        text;
  v_started_at    timestamptz;
  v_id            uuid;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_tool FROM agents.tools_registry WHERE id = p_tool_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'tool not found' USING ERRCODE = 'P0002';
  END IF;
  IF v_tool.status <> 'active' THEN
    RAISE EXCEPTION 'tool % is %', v_tool.key, v_tool.status USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_assignment
    FROM agents.tool_assignments
   WHERE ai_lenser_id = p_ai_lenser_id AND tool_id = p_tool_id;
  IF NOT FOUND OR v_assignment.allowed IS DISTINCT FROM true THEN
    RAISE EXCEPTION 'tool % not assigned to agent', v_tool.key USING ERRCODE = '42501';
  END IF;

  IF v_assignment.profile_id IS NOT NULL THEN
    SELECT * INTO v_profile FROM agents.tool_profiles WHERE id = v_assignment.profile_id;
    IF FOUND AND v_profile.requires_approval THEN
      v_requires := true;
    END IF;
  END IF;

  IF v_tool.requires_approval OR v_tool.egress_class = 'write' THEN
    v_requires := true;
  END IF;

  IF v_requires THEN
    v_appr_status := 'pending';
    v_status      := 'pending';
    v_started_at  := NULL;
  ELSE
    v_appr_status := 'not_required';
    v_status      := 'running';
    v_started_at  := now();
  END IF;

  INSERT INTO agents.tool_invocations (
    team_run_id, agent_run_step_id, tool_id, ai_lenser_id,
    input, status, approval_status, approval_required, started_at
  )
  VALUES (
    p_team_run_id, p_agent_run_step_id, p_tool_id, p_ai_lenser_id,
    COALESCE(p_input, '{}'::jsonb), v_status, v_appr_status, v_requires, v_started_at
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_invoke_tool"("p_team_run_id" "uuid", "p_tool_id" "uuid", "p_ai_lenser_id" "uuid", "p_input" "jsonb", "p_agent_run_step_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_is_notification_blocked"("p_actor_id" "uuid", "p_recipient_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1
    FROM   lensers.relationships
    WHERE  source_profile_id = p_recipient_id
      AND  target_profile_id = p_actor_id
      AND  status = 'blocked'
      AND  removed_at IS NULL
  );
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_is_notification_blocked failed: %', SQLERRM;
  RETURN false;  -- fail-open: never suppress by accident
END;
$$;


