CREATE OR REPLACE FUNCTION "public"."fn_kill_switch_activate"("p_scope" "text", "p_target_id" "uuid" DEFAULT NULL::"uuid", "p_reason" "text" DEFAULT 'emergency stop'::"text", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'admin', 'public', 'lensers'
    AS $$
DECLARE
  v_operator_id UUID;
  v_switch_id   UUID;
BEGIN
  -- Admin-only
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'kill_switch_activate_forbidden: admin role required';
  END IF;

  SELECT id INTO v_operator_id
  FROM   lensers.profiles
  WHERE  user_id = auth.uid()
  LIMIT  1;

  IF v_operator_id IS NULL THEN
    RAISE EXCEPTION 'kill_switch_activate_no_profile: lenser profile not found';
  END IF;

  INSERT INTO admin.kill_switches (scope, target_id, operator_id, reason, expires_at)
  VALUES (p_scope, p_target_id, v_operator_id, p_reason, p_expires_at)
  RETURNING id INTO v_switch_id;

  -- Audit trail
  INSERT INTO audit.events (event_type, actor_type, actor_id, severity, payload)
  VALUES (
    'kill_switch.activated',
    'lenser',
    v_operator_id,
    'warn',
    jsonb_build_object(
      'switch_id', v_switch_id,
      'scope',     p_scope,
      'target_id', p_target_id,
      'reason',    p_reason
    )
  );

  RETURN v_switch_id;
END;
$$;


ALTER FUNCTION "public"."fn_kill_switch_activate"("p_scope" "text", "p_target_id" "uuid", "p_reason" "text", "p_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_kill_switch_active"("p_scope" "text", "p_target_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'admin', 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM   admin.kill_switches ks
    WHERE  ks.lifted_at IS NULL
    AND    (ks.expires_at IS NULL OR ks.expires_at > now())
    AND    (
             -- System-wide switch halts everything
             ks.scope = 'system'
             OR
             -- Scope + target match
             (ks.scope = p_scope AND ks.target_id = p_target_id)
           )
  );
$$;


ALTER FUNCTION "public"."fn_kill_switch_active"("p_scope" "text", "p_target_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_kill_switch_lift"("p_switch_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'admin', 'public', 'lensers'
    AS $$
DECLARE
  v_operator_id UUID;
  v_switch      admin.kill_switches%ROWTYPE;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'kill_switch_lift_forbidden: admin role required';
  END IF;

  SELECT * INTO v_switch FROM admin.kill_switches WHERE id = p_switch_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'kill_switch_not_found: %', p_switch_id;
  END IF;

  IF v_switch.lifted_at IS NOT NULL THEN
    RAISE EXCEPTION 'kill_switch_already_lifted: %', p_switch_id;
  END IF;

  UPDATE admin.kill_switches SET lifted_at = now() WHERE id = p_switch_id;

  SELECT id INTO v_operator_id
  FROM   lensers.profiles
  WHERE  user_id = auth.uid()
  LIMIT  1;

  INSERT INTO audit.events (event_type, actor_type, actor_id, severity, payload)
  VALUES (
    'kill_switch.lifted',
    'lenser',
    v_operator_id,
    'info',
    jsonb_build_object(
      'switch_id',     p_switch_id,
      'original_scope', v_switch.scope,
      'target_id',     v_switch.target_id
    )
  );
END;
$$;


ALTER FUNCTION "public"."fn_kill_switch_lift"("p_switch_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_kill_switch_list"() RETURNS TABLE("id" "uuid", "scope" "text", "target_id" "uuid", "reason" "text", "expires_at" timestamp with time zone, "activated_at" timestamp with time zone, "lifted_at" timestamp with time zone, "operator_handle" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'admin', 'public', 'lensers'
    AS $$
  SELECT
    ks.id,
    ks.scope,
    ks.target_id,
    ks.reason,
    ks.expires_at,
    ks.activated_at,
    ks.lifted_at,
    p.handle AS operator_handle
  FROM  admin.kill_switches ks
  LEFT  JOIN lensers.profiles p ON p.id = ks.operator_id
  ORDER BY ks.activated_at DESC;
$$;


