CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_leaderboard"("p_period" "text" DEFAULT 'all_time'::"text", "p_limit" integer DEFAULT 20) RETURNS TABLE("lenser_id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "total_xp" bigint, "current_level" integer, "lenser_score" double precision, "rank" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'xp', 'lenses', 'content'
    AS $$
WITH ranked AS (
  SELECT
    lp.id            AS lenser_id,
    lp.handle,
    lp.display_name,
    lp.avatar_url,
    COALESCE(xt.total_xp,      0)::bigint AS total_xp,
    COALESCE(xt.current_level, 1)          AS current_level,
    ROW_NUMBER() OVER (ORDER BY COALESCE(xt.total_xp, 0) DESC) AS rank
  FROM lensers.profiles lp
  LEFT JOIN (
    SELECT t.lenser_id,
           SUM(t.total_xp)       AS total_xp,
           MAX(t.current_level)  AS current_level
    FROM xp.totals t
    GROUP BY t.lenser_id
  ) xt ON xt.lenser_id = lp.id
  WHERE lp.status              = 'active'
    AND lp.visibility          = 'public'
    AND lp.deletion_requested_at IS NULL
    AND CASE p_period
          WHEN 'weekly'  THEN lp.last_active_at > now() - interval '7 days'
          WHEN 'monthly' THEN lp.last_active_at > now() - interval '30 days'
          ELSE true
        END
  ORDER BY COALESCE(xt.total_xp, 0) DESC
  -- clamp: at least 1, at most 100; negative or zero inputs become 1
  LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 20), 100))
)
SELECT
  r.lenser_id,
  r.handle,
  r.display_name,
  r.avatar_url,
  r.total_xp,
  r.current_level,
  (
    0.7 * log(GREATEST(1.0, r.total_xp::double precision))
    + 0.3 * log(GREATEST(1.0, COALESCE(re7.cnt, 0)::double precision))
  ) AS lenser_score,
  r.rank
FROM ranked r
LEFT JOIN LATERAL (
  SELECT count(*) AS cnt
  FROM (
    SELECT 1
    FROM content.reactions tr
    JOIN content.threads t ON t.id = tr.entity_id AND t.lenser_id = r.lenser_id
    WHERE tr.entity_type = 'thread'
      AND tr.created_at > now() - interval '7 days'
    UNION ALL
    SELECT 1
    FROM content.reactions pr
    JOIN lenses.lenses pt ON pt.id = pr.entity_id AND pt.lenser_id = r.lenser_id
    WHERE pr.entity_type = 'lens'
      AND pr.created_at > now() - interval '7 days'
  ) x
) re7 ON true
ORDER BY r.rank;
$$;


ALTER FUNCTION "public"."fn_lensers_get_leaderboard"("p_period" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_preferences"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
    v_uid  uuid;
    v_row  lensers.preferences;
BEGIN
    v_uid := auth.uid();
    IF v_uid IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT p.*
      INTO v_row
      FROM lensers.preferences p
      JOIN lensers.profiles    pr ON pr.id = p.lenser_id
     WHERE pr.user_id = v_uid;

    IF NOT FOUND THEN
        RETURN '{}'::jsonb;
    END IF;

    RETURN to_jsonb(v_row);
END;
$$;


