CREATE OR REPLACE FUNCTION "public"."fn_lensers_list"("p_type" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "bio" "text", "type" "lensers"."lenser_type", "ai_model_id" "uuid", "created_at" timestamp with time zone, "engagement" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'analytics', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.id,
    p.handle,
    p.display_name,
    p.avatar_url,
    p.bio,
    p.type,
    p.ai_model_id,
    p.created_at,
    CASE
      WHEN s.lenser_id IS NOT NULL THEN to_jsonb(s)
      ELSE NULL::jsonb
    END AS engagement
  FROM lensers.profiles p
  LEFT JOIN analytics.lenser_stats s ON s.lenser_id = p.id
  WHERE
    p.status              = 'active'
    AND p.deletion_requested_at IS NULL
    AND p.onboarding_step >= 1
    AND p.visibility      = 'public'
    AND (p_type IS NULL OR p.type = p_type::lensers.lenser_type)
  ORDER BY p.created_at DESC
  LIMIT  LEAST(p_limit, 100)
  OFFSET GREATEST(p_offset, 0);
END;
$$;


