CREATE OR REPLACE FUNCTION "public"."fn_media_unbind_attachment"("p_entity_type" "text", "p_entity_id" "uuid", "p_binding_key" "text" DEFAULT '_default'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
