CREATE OR REPLACE FUNCTION "public"."fn_notify_battle_result"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_battle        battles.battles;
  v_winner        battles.contenders;
  v_action_url    TEXT;
  v_email_payload JSONB;
  v_voter_ids     UUID[];
  v_contender     RECORD;
  v_outcome_type  TEXT;
  v_body_text     TEXT;
BEGIN
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id;
  IF NOT FOUND THEN RETURN; END IF;

  IF v_battle.winner_contender_id IS NOT NULL THEN
    SELECT * INTO v_winner FROM battles.contenders WHERE id = v_battle.winner_contender_id;
    v_body_text := 'Winner: ' || COALESCE(v_winner.display_name, 'Unknown');
  ELSE
    v_body_text := 'The battle ended in a draw.';
  END IF;

  v_action_url := '/battles/' || v_battle.slug || '/result';

  -- ── Contenders: differentiated battle_won / battle_lost ──────────────────
  FOR v_contender IN
    SELECT
      cem.profile_id                                                AS lenser_id,
      c.id                                                          AS contender_id,
      (c.id = v_battle.winner_contender_id)                        AS is_winner
    FROM   battles.contenders c
    JOIN   battles.contender_entity_map cem ON cem.contender_id = c.id
    WHERE  c.battle_id     = p_battle_id
      AND  cem.profile_id  IS NOT NULL
  LOOP
    v_outcome_type := CASE WHEN v_contender.is_winner THEN 'battle_won' ELSE 'battle_lost' END;

    PERFORM public.fn_insert_notification(
      v_contender.lenser_id,
      v_outcome_type,
      'Battle result: ' || v_battle.title,
      v_body_text,
      v_action_url,
      jsonb_build_object(
        'battle_id',     p_battle_id,
        'battle_slug',   v_battle.slug,
        'contender_id',  v_contender.contender_id,
        'winner_id',     v_battle.winner_contender_id,
        'winner_name',   COALESCE(v_winner.display_name, NULL),
        'is_winner',     v_contender.is_winner
      )
      -- p_actor_id = NULL: system outcome, skip block/mute gate
    );
  END LOOP;

  -- ── Voters: keep generic battle_result ───────────────────────────────────
  SELECT array_agg(DISTINCT voter_lenser_id) INTO v_voter_ids
  FROM   battles.votes
  WHERE  battle_id         = p_battle_id
    AND  voter_lenser_id   IS NOT NULL;

  IF v_voter_ids IS NOT NULL AND array_length(v_voter_ids, 1) > 0 THEN
    INSERT INTO public.notifications (lenser_id, type, title, body, action_url, metadata)
    SELECT
      unnest(v_voter_ids),
      'battle_result',
      'Battle result: ' || v_battle.title,
      v_body_text,
      v_action_url,
      jsonb_build_object(
        'battle_id',   p_battle_id,
        'battle_slug', v_battle.slug,
        'winner_id',   v_battle.winner_contender_id,
        'winner_name', COALESCE(v_winner.display_name, NULL)
      )
    ON CONFLICT DO NOTHING;
  END IF;

  -- ── Email edge function (unchanged) ───────────────────────────────────────
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_net') THEN
    SELECT jsonb_build_object(
      'battle_id',        p_battle_id,
      'battle_title',     v_battle.title,
      'battle_slug',      v_battle.slug,
      'winner_name',      COALESCE(v_winner.display_name, NULL),
      'recipient_emails', (
        SELECT jsonb_agg(email)
        FROM   lensers.profiles
        WHERE  id = ANY(v_voter_ids)
          AND  email IS NOT NULL
      )
    ) INTO v_email_payload;

    PERFORM net.http_post(
      url     := current_setting('app.supabase_url', true) || '/functions/v1/send-battle-result-email',
      headers := jsonb_build_object(
        'Content-Type',  'application/json',
        'Authorization', 'Bearer ' || current_setting('app.service_role_key', true)
      ),
      body    := v_email_payload
    );
  END IF;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_notify_battle_result failed for battle %: %', p_battle_id, SQLERRM;
END;
$$;


ALTER FUNCTION "public"."fn_notify_battle_result"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_ops_submit_contact"("p_name" "text", "p_email" "text", "p_subject" "text", "p_message" "text", "p_kvkk_approved" boolean DEFAULT false, "p_ip_address" "text" DEFAULT NULL::"text", "p_user_agent" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'lensers', 'auth'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  -- Basic sanity guards
  IF trim(p_name) = '' OR trim(p_email) = '' OR trim(p_message) = '' THEN
    RAISE EXCEPTION 'name, email, and message are required' USING ERRCODE = '22023';
  END IF;

  IF NOT p_kvkk_approved THEN
    RAISE EXCEPTION 'KVKK consent is required' USING ERRCODE = '22023';
  END IF;

  -- Resolve optional lenser_id from auth context
  IF auth.uid() IS NOT NULL THEN
    SELECT id INTO v_lenser_id
    FROM lensers.profiles
    WHERE user_id = auth.uid()
    LIMIT 1;
  END IF;

  INSERT INTO analytics.contact (
    lenser_id,
    name,
    email,
    subject,
    message,
    kvkk_approved,
    ip_address,
    user_agent
  ) VALUES (
    v_lenser_id,
    trim(p_name),
    lower(trim(p_email)),
    trim(p_subject),
    trim(p_message),
    p_kvkk_approved,
    p_ip_address::inet,
    p_user_agent
  );
END;
$$;


ALTER FUNCTION "public"."fn_ops_submit_contact"("p_name" "text", "p_email" "text", "p_subject" "text", "p_message" "text", "p_kvkk_approved" boolean, "p_ip_address" "text", "p_user_agent" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_ops_submit_contact"("p_name" "text", "p_email" "text", "p_subject" "text", "p_message" "text", "p_kvkk_approved" boolean, "p_ip_address" "text", "p_user_agent" "text") IS 'Inserts a contact form submission into ops.contact. Accessible to anonymous users.';



CREATE OR REPLACE FUNCTION "public"."fn_pause_agent"("p_ai_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.workspace_settings (ai_lenser_id, agent_paused)
  VALUES (p_ai_lenser_id, true)
  ON CONFLICT (ai_lenser_id) DO UPDATE
    SET agent_paused = true,
        updated_at   = now();

  INSERT INTO agents.policy_evaluations (
    ai_lenser_id,
    evaluation_point,
    policy_type,
    verdict,
    reason,
    context,
    evaluated_at
  ) VALUES (
    p_ai_lenser_id,
    'pre_run',
    'pause',
    'deny',
    'agent paused by owner',
    jsonb_build_object('paused_by', auth.uid()),
    now()
  );
END;
$$;


