CREATE OR REPLACE FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'xp', 'battles', 'public'
    AS $$
DECLARE
  v_score     integer := 0;
  v_bio       text;
  v_avatar    text;
  v_location  text;
  v_website   text;
  v_battles   bigint;
  v_total_xp  bigint;
BEGIN
  SELECT
    p.bio,
    p.avatar_url,
    p.location,
    p.website_url
  INTO v_bio, v_avatar, v_location, v_website
  FROM lensers.profiles p
  WHERE p.id = p_lenser_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  IF v_bio IS NOT NULL AND length(trim(v_bio)) > 0 THEN
    v_score := v_score + 25;
  END IF;
  IF v_avatar IS NOT NULL AND length(trim(v_avatar)) > 0 THEN
    v_score := v_score + 25;
  END IF;
  IF v_location IS NOT NULL AND length(trim(v_location)) > 0 THEN
    v_score := v_score + 15;
  END IF;
  IF v_website IS NOT NULL AND length(trim(v_website)) > 0 THEN
    v_score := v_score + 15;
  END IF;

  -- Battle participation ('cancelled' is not a valid battles.battle_status_enum value)
  SELECT COUNT(*) INTO v_battles
  FROM battles.contenders bc
  JOIN battles.battles b ON b.id = bc.battle_id
  WHERE bc.contender_ref_id = p_lenser_id
    AND b.status <> 'draft'::battles.battle_status_enum;

  IF v_battles > 0 THEN
    v_score := v_score + 10;
  END IF;

  -- XP earned (any positive amount)
  SELECT COALESCE(SUM(xp), 0) INTO v_total_xp
  FROM xp.events
  WHERE lenser_id = p_lenser_id;

  IF v_total_xp > 0 THEN
    v_score := v_score + 10;
  END IF;

  RETURN LEAST(v_score, 100);
END;
$$;


ALTER FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") IS 'Returns a 0–100 profile completion score. Breakdown: bio +25, avatar +25, location +15, website +15, battles >0 +10, XP >0 +10.';



CREATE OR REPLACE FUNCTION "public"."fn_promote_scratchpad_to_memory"("p_run_id" "uuid", "p_memory_profile_id" "uuid") RETURNS "agents"."memory_profiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_run     agents.scratchpad_runs;
  v_profile agents.memory_profiles;
BEGIN
  SELECT * INTO v_run FROM agents.scratchpad_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'scratchpad run not found' USING ERRCODE = 'P0002';
  END IF;

  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_memory_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_run.ai_lenser_id)
     OR NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;

  UPDATE agents.memory_profiles
  SET seed = seed || jsonb_build_array(jsonb_build_object(
        'source', 'scratchpad',
        'run_id', v_run.id,
        'prompt', v_run.prompt,
        'output', v_run.output,
        'promoted_at', now()
      )),
      updated_at = now()
  WHERE id = p_memory_profile_id
  RETURNING * INTO v_profile;

  RETURN v_profile;
END;
$$;


ALTER FUNCTION "public"."fn_promote_scratchpad_to_memory"("p_run_id" "uuid", "p_memory_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'extensions', 'public'
    AS $$
DECLARE
  v_lenser_id  uuid  := lensers.get_auth_lenser_id();
  v_rules_json jsonb;
  v_hash       text;
BEGIN
  -- Authorization: only creator may publish; battle must be in draft
  IF NOT EXISTS (
    SELECT 1 FROM battles.battles
    WHERE id = p_battle_id
      AND creator_lenser_id = v_lenser_id
      AND status = 'draft'
  ) THEN
    RAISE EXCEPTION 'not_authorized_or_invalid_state';
  END IF;

  -- Build frozen rules snapshot
  SELECT jsonb_build_object(
    'title',             title,
    'task_prompt',       task_prompt,
    'battle_type',       battle_type,
    'voter_eligibility', voter_eligibility,
    'max_contenders',    max_contenders,
    'rubric_id',         rubric_id,
    'handicap_config',   handicap_config,
    'published_at',      now()
  )
  INTO v_rules_json
  FROM battles.battles
  WHERE id = p_battle_id;

  -- SHA-256 hash via pgcrypto (extensions schema is now in search_path)
  v_hash := encode(digest(v_rules_json::text, 'sha256'), 'hex');

  -- Insert rule snapshot (append-only)
  INSERT INTO battles.rule_snapshots (battle_id, snapshot_hash, rules_json, created_by)
  VALUES (p_battle_id, v_hash, v_rules_json, v_lenser_id);

  -- Open the battle
  UPDATE battles.battles
  SET status = 'open', published_at = now()
  WHERE id = p_battle_id;

  -- Attestation (append-only)
  INSERT INTO audit.attestations (
    entity_type, entity_id, attested_by, attestation_type, proof_payload
  )
  VALUES (
    'battle', p_battle_id, v_lenser_id, 'battle_published',
    jsonb_build_object('snapshot_hash', v_hash, 'battle_id', p_battle_id)
  );

  RETURN jsonb_build_object(
    'snapshot_hash', v_hash,
    'status',        'open',
    'battle_id',     p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") IS 'Atomically publishes a battle: freezes rules into rule_snapshots, transitions status to ''open'', and records an audit attestation. Phase A fix: search_path now includes extensions for pgcrypto digest(). Only the battle creator may call this. Battle must be in ''draft'' status. Direct UPDATE on battles.battles.status is restricted to service_role via column-level revoke (see A3 below).';



CREATE OR REPLACE FUNCTION "public"."fn_purge_due_accounts"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'analytics'
    AS $$
DECLARE
  v_count   int := 0;
  v_profile RECORD;
BEGIN
  FOR v_profile IN
    SELECT id, user_id, deletion_deadline_at
    FROM lensers.profiles
    WHERE status = 'pending_deletion'
      AND deletion_deadline_at <= now() - interval '1 hour'
  LOOP
    UPDATE lensers.profiles
    SET display_name = 'Deleted User',
        handle       = 'deleted_' || v_profile.id::text,
        bio          = null,
        headline     = null,
        avatar_url   = null,
        banner_url   = null,
        website_url  = null,
        preferences  = null,
        status       = 'deleted',
        updated_at   = now()
    WHERE id = v_profile.id;

    PERFORM lensers.log_account_lifecycle_event(
      v_profile.id,
      v_profile.user_id,
      'deletion_completed',
      'pending_deletion'::lensers.lenser_status,
      'deleted'::lensers.lenser_status,
      'system_job',
      jsonb_build_object(
        'deletion_deadline_at',     v_profile.deletion_deadline_at,
        'purged_after_grace_period', true
      )
    );

    DELETE FROM lensers.relationships
    WHERE source_profile_id = v_profile.id OR target_profile_id = v_profile.id;

    DELETE FROM lensers.social_links WHERE lenser_id = v_profile.id;

    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."fn_purge_due_accounts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_read_memory_entries"("p_profile_id" "uuid", "p_scope" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10, "p_team_run_id" "uuid" DEFAULT NULL::"uuid") RETURNS SETOF "agents"."memories"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_profile agents.memory_profiles;
  v_row     agents.memories;
BEGIN
  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  FOR v_row IN
    SELECT *
    FROM agents.memories
    WHERE profile_id = p_profile_id
      AND is_redacted = false
      AND (p_scope IS NULL OR scope = p_scope)
      AND (expires_at IS NULL OR expires_at > now())
    ORDER BY confidence DESC, created_at DESC
    LIMIT GREATEST(COALESCE(p_limit, 10), 1)
  LOOP
    INSERT INTO agents.memory_access_logs (memory_id, team_run_id, action, context)
    VALUES (v_row.id, p_team_run_id, 'read',
            jsonb_build_object('scope', p_scope, 'profile_id', p_profile_id));
    RETURN NEXT v_row;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_read_memory_entries"("p_profile_id" "uuid", "p_scope" "text", "p_limit" integer, "p_team_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_record_run_incident"("p_run_report_id" "uuid", "p_incident_type" "text", "p_severity" "text", "p_title" "text", "p_description" "text", "p_context" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_report    agents.run_reports;
  v_id        uuid;
BEGIN
  SELECT * INTO v_report
    FROM agents.run_reports
   WHERE id = p_run_report_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'run report not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_report.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  IF p_incident_type NOT IN (
    'tool_failure','budget_exceeded','policy_violation','timeout',
    'step_failure','approval_rejected','kill_switch'
  ) THEN
    RAISE EXCEPTION 'invalid incident_type: %', p_incident_type USING ERRCODE = '22023';
  END IF;

  IF p_severity NOT IN ('low','medium','high','critical') THEN
    RAISE EXCEPTION 'invalid severity: %', p_severity USING ERRCODE = '22023';
  END IF;

  INSERT INTO agents.run_incidents (
    run_report_id,
    ai_lenser_id,
    incident_type,
    severity,
    title,
    description,
    context
  ) VALUES (
    p_run_report_id,
    v_report.ai_lenser_id,
    p_incident_type,
    p_severity,
    p_title,
    p_description,
    COALESCE(p_context, '{}'::jsonb)
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_record_run_incident"("p_run_report_id" "uuid", "p_incident_type" "text", "p_severity" "text", "p_title" "text", "p_description" "text", "p_context" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
  v_id        uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    JOIN lenses.workflows w ON w.id = r.workflow_id
    WHERE r.id = p_target_run_id
      AND (w.lenser_id = v_caller_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller cannot record provenance for run %', p_target_run_id
      USING ERRCODE = '42501';
  END IF;

  INSERT INTO lenses.workflow_run_provenance (
    source_run_id, source_node_id, source_output_path,
    target_run_id, target_node_id, target_input_path,
    transform
  )
  VALUES (
    p_source_run_id, p_source_node_id, p_source_output_path,
    p_target_run_id, p_target_node_id, p_target_input_path,
    p_transform
  )
  ON CONFLICT (source_run_id, source_node_id, source_output_path,
               target_run_id, target_node_id, target_input_path)
  DO UPDATE SET transform = COALESCE(EXCLUDED.transform, workflow_run_provenance.transform)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb") IS 'Records a field-level data handoff. Idempotent on the (source, target, path) tuple. Transform JSON may carry mapping expression captured at edge-binding time.';



