CREATE OR REPLACE FUNCTION "public"."fn_reorder_workflow_phases"("p_workflow_id" "uuid", "p_ordered_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_id   uuid;
  v_idx  integer := 0;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id AND w.lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RAISE EXCEPTION 'reorder_phases_forbidden' USING ERRCODE = '42501';
  END IF;

  FOREACH v_id IN ARRAY p_ordered_ids LOOP
    UPDATE lenses.workflow_phases SET ordinal = v_idx WHERE id = v_id AND workflow_id = p_workflow_id;
    v_idx := v_idx + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_reorder_workflow_phases"("p_workflow_id" "uuid", "p_ordered_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_reorder_workflow_tasks"("p_phase_id" "uuid", "p_ordered_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_id   uuid;
  v_idx  integer := 0;
BEGIN
  -- Verify ownership via phase → workflow
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflow_phases wp
    JOIN lenses.workflows w ON w.id = wp.workflow_id
    WHERE wp.id = p_phase_id AND w.lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RAISE EXCEPTION 'reorder_tasks_forbidden' USING ERRCODE = '42501';
  END IF;

  FOREACH v_id IN ARRAY p_ordered_ids LOOP
    UPDATE lenses.workflow_tasks SET ordinal = v_idx WHERE id = v_id AND phase_id = p_phase_id;
    v_idx := v_idx + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_reorder_workflow_tasks"("p_phase_id" "uuid", "p_ordered_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_request_follow"("p_target_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_source_id     uuid;
  v_target        RECORD;
  v_existing      lensers.relationship_status;
  v_new_status    lensers.relationship_status;
BEGIN
  SELECT id INTO v_source_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_source_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required or profile not found';
  END IF;

  IF v_source_id = p_target_profile_id THEN
    RAISE EXCEPTION 'Cannot follow yourself';
  END IF;

  -- Check target exists and is active
  SELECT p.id, p.status, p.visibility INTO v_target
  FROM lensers.profiles p WHERE p.id = p_target_profile_id;

  IF NOT FOUND OR v_target.status NOT IN ('active') THEN
    RETURN jsonb_build_object('status', 'rejected', 'reason', 'target_unavailable');
  END IF;

  -- Check if blocked in either direction
  IF EXISTS (
    SELECT 1 FROM lensers.relationships
    WHERE status = 'blocked'
      AND (
        (source_profile_id = v_source_id AND target_profile_id = p_target_profile_id)
        OR (source_profile_id = p_target_profile_id AND target_profile_id = v_source_id)
      )
  ) THEN
    RETURN jsonb_build_object('status', 'rejected', 'reason', 'blocked');
  END IF;

  -- Check existing relationship
  SELECT r.status INTO v_existing
  FROM lensers.relationships r
  WHERE r.source_profile_id = v_source_id AND r.target_profile_id = p_target_profile_id;

  IF v_existing = 'accepted' THEN
    RETURN jsonb_build_object('status', 'accepted', 'reason', 'already_following');
  END IF;

  IF v_existing = 'pending' THEN
    RETURN jsonb_build_object('status', 'pending', 'reason', 'already_pending');
  END IF;

  -- Determine status based on target visibility
  IF v_target.visibility IN ('public', 'community') THEN
    v_new_status := 'accepted';
  ELSE
    v_new_status := 'pending';
  END IF;

  INSERT INTO lensers.relationships (source_profile_id, target_profile_id, status, accepted_at)
  VALUES (
    v_source_id,
    p_target_profile_id,
    v_new_status,
    CASE WHEN v_new_status = 'accepted' THEN now() ELSE null END
  )
  ON CONFLICT (source_profile_id, target_profile_id)
  DO UPDATE SET
    status       = v_new_status,
    requested_at = now(),
    responded_at = null,
    accepted_at  = CASE WHEN v_new_status = 'accepted' THEN now() ELSE null END,
    removed_at   = null;

  RETURN jsonb_build_object('status', v_new_status::text);
END;
$$;


ALTER FUNCTION "public"."fn_request_follow"("p_target_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_request_workspace_deletion"("p_ai_lenser_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "agents"."workspace_settings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_row agents.workspace_settings;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.workspace_settings (ai_lenser_id)
  VALUES (p_ai_lenser_id)
  ON CONFLICT (ai_lenser_id) DO NOTHING;

  UPDATE agents.workspace_settings
  SET metadata = metadata || jsonb_build_object(
        'deletion_requested_at', now(),
        'deletion_reason',       p_reason
      ),
      updated_at = now()
  WHERE ai_lenser_id = p_ai_lenser_id
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


