CREATE OR REPLACE FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_actor UUID;
BEGIN
  v_actor := auth.uid();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'Forbidden: super_admin required' USING ERRCODE = 'P0003';
  END IF;

  UPDATE audit.vote_anomalies
     SET resolved_at  = now(),
         resolved_by  = v_actor
   WHERE id = p_anomaly_id
     AND resolved_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Anomaly not found or already resolved' USING ERRCODE = 'P0002';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") IS 'CA: Marks an anomaly resolved. Requires super_admin.';



CREATE OR REPLACE FUNCTION "public"."fn_resume_agent"("p_ai_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.workspace_settings (ai_lenser_id, agent_paused)
  VALUES (p_ai_lenser_id, false)
  ON CONFLICT (ai_lenser_id) DO UPDATE
    SET agent_paused = false,
        updated_at   = now();
END;
$$;


ALTER FUNCTION "public"."fn_resume_agent"("p_ai_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_retry_agent_run"("p_ai_lenser_id" "uuid", "p_run_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_run     agents.team_runs;
  v_new_id  uuid;
BEGIN
  SELECT * INTO v_run
    FROM agents.team_runs
   WHERE id = p_run_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'team run not found' USING ERRCODE = 'P0002';
  END IF;

  IF v_run.ai_lenser_id <> p_ai_lenser_id THEN
    RAISE EXCEPTION 'run does not belong to this agent' USING ERRCODE = '42501';
  END IF;

  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  IF v_run.status NOT IN ('failed', 'cancelled', 'completed') THEN
    RAISE EXCEPTION 'only terminal runs can be retried' USING ERRCODE = '22023';
  END IF;

  INSERT INTO agents.team_runs (
    ai_lenser_id,
    team_id,
    workflow_id,
    workflow_assignment_id,
    status,
    approval_status,
    metadata
  ) VALUES (
    v_run.ai_lenser_id,
    v_run.team_id,
    v_run.workflow_id,
    v_run.workflow_assignment_id,
    'queued',
    'pending',
    jsonb_build_object('retried_from', v_run.id)
  )
  RETURNING id INTO v_new_id;

  INSERT INTO agents.agent_run_events (
    team_run_id,
    event_type,
    payload,
    occurred_at
  ) VALUES (
    v_new_id,
    'run_retried',
    jsonb_build_object(
      'original_run_id', v_run.id,
      'retried_by',      auth.uid()
    ),
    now()
  );

  RETURN v_new_id::text;
END;
$$;


ALTER FUNCTION "public"."fn_retry_agent_run"("p_ai_lenser_id" "uuid", "p_run_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_retry_agent_run"("p_ai_lenser_id" "uuid", "p_run_id" "uuid") IS 'Clone a terminal (failed/cancelled/completed) team_run as a new queued run. Returns the new run id. Authorization via agents.can_manage_ai_lenser.';



