CREATE OR REPLACE FUNCTION "public"."fn_revoke_agent_ownership"("p_ownership_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_ownership agents.ownerships%ROWTYPE;
BEGIN
  SELECT *
  INTO v_ownership
  FROM agents.ownerships o
  WHERE o.id = p_ownership_id
  LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ownership grant not found.'
      USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_ownership.ai_lenser_id) THEN
    RAISE EXCEPTION 'Not authorized to revoke this delegate.'
      USING ERRCODE = '42501';
  END IF;

  IF v_ownership.role = 'owner' THEN
    RAISE EXCEPTION 'The primary owner cannot be revoked through this RPC.'
      USING ERRCODE = '22023';
  END IF;

  UPDATE agents.ownerships
  SET revoked_at = now()
  WHERE id = p_ownership_id;
END;
$$;


ALTER FUNCTION "public"."fn_revoke_agent_ownership"("p_ownership_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_revoke_agent_ownership"("p_ownership_id" "uuid") IS 'Revokes a co_owner or operator delegation for an AI Lenser. The primary owner must be handled through a dedicated ownership-transfer flow.';



