ALTER FUNCTION "public"."fn_revoke_api_key"("p_key_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_revoke_api_key"("p_key_id" "uuid") IS 'Public REST wrapper for ai.fn_revoke_api_key. Soft-revokes a BYOK API key — sets is_active=false, records revoked_at. Only the key owner can revoke (enforced inside ai.fn_revoke_api_key). The ai schema is not exposed in PostgREST — this wrapper is the only REST-callable entry point for key revocation. Added in migration 000057.';



CREATE OR REPLACE FUNCTION "public"."fn_revoke_standing_approval"("p_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_caller       uuid := lensers.get_auth_lenser_id();
  v_ai_lenser_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT ai_lenser_id INTO v_ai_lenser_id
  FROM   agents.standing_approvals
  WHERE  id = p_id;

  IF v_ai_lenser_id IS NULL THEN
    RAISE EXCEPTION 'standing_approval_not_found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_ai_lenser_id) THEN
    RAISE EXCEPTION 'not_owner_of_ai_lenser' USING ERRCODE = '42501';
  END IF;

  UPDATE agents.standing_approvals
  SET    revoked_at = now()
  WHERE  id = p_id
    AND  revoked_at IS NULL;

  INSERT INTO agents.action_logs (
    ai_lenser_id, action_type, result, metadata
  ) VALUES (
    v_ai_lenser_id,
    'standing_approval_revoked',
    'success',
    jsonb_build_object(
      'standing_approval_id', p_id,
      'revoked_by',           v_caller
    )
  );
END;
$$;


ALTER FUNCTION "public"."fn_revoke_standing_approval"("p_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_revoke_standing_approval"("p_id" "uuid") IS 'Phase Q2: revokes a standing approval (sets revoked_at=now()). Owner-only; writes an action_logs entry.';



