CREATE OR REPLACE FUNCTION "public"."fn_submit_vote"("p_battle_id" "uuid", "p_voted_contender_id" "uuid", "p_vote_value" "battles"."vote_value_enum", "p_is_draw" boolean DEFAULT false, "p_rationale" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
  v_vote_id   uuid;
BEGIN
  -- Guard: battle must be in voting phase
  IF NOT EXISTS (
    SELECT 1 FROM battles.battles
    WHERE id = p_battle_id AND status = 'voting'
  ) THEN
    RAISE EXCEPTION 'battle_not_in_voting_phase: %', p_battle_id;
  END IF;

  -- Guard: contender must belong to the battle
  IF NOT EXISTS (
    SELECT 1 FROM battles.contenders
    WHERE id = p_voted_contender_id AND battle_id = p_battle_id
  ) THEN
    RAISE EXCEPTION 'contender_not_in_battle: %', p_voted_contender_id;
  END IF;

  -- Insert vote (uq_votes_battle_voter unique constraint prevents double-vote)
  INSERT INTO battles.votes (
    battle_id, voter_lenser_id, vote_value,
    voted_contender_id, is_draw, rationale
  )
  VALUES (
    p_battle_id, v_lenser_id, p_vote_value,
    p_voted_contender_id, p_is_draw, p_rationale
  )
  RETURNING id INTO v_vote_id;

  -- Upsert vote aggregates (atomic counter update)
  INSERT INTO battles.vote_aggregates (
    battle_id, contender_id,
    raw_vote_count, weighted_vote_sum, draw_count
  )
  VALUES (
    p_battle_id, p_voted_contender_id,
    1, 1, CASE WHEN p_is_draw THEN 1 ELSE 0 END
  )
  ON CONFLICT (battle_id, contender_id) DO UPDATE SET
    raw_vote_count    = battles.vote_aggregates.raw_vote_count + 1,
    weighted_vote_sum = battles.vote_aggregates.weighted_vote_sum + 1,
    draw_count        = battles.vote_aggregates.draw_count +
                        CASE WHEN p_is_draw THEN 1 ELSE 0 END,
    updated_at        = now();

  -- Increment denormalized total on the battle row
  UPDATE battles.battles
  SET total_vote_count = total_vote_count + 1
  WHERE id = p_battle_id;

  -- TODO Phase C: award XP via xp rule lookup once rule_id for 'BATTLE_VOTED' is known.
  -- INSERT INTO xp.events (lenser_id, app_id, rule_id, action_key, xp, base_xp, source,
  --                        source_ref_type, source_ref_id)
  -- VALUES (v_lenser_id, <app_id>, <rule_id>, 'BATTLE_VOTED', <xp>, <base_xp>, 'votes',
  --         'battle', p_battle_id);

  RETURN jsonb_build_object(
    'vote_id',   v_vote_id,
    'status',    'success',
    'battle_id', p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_submit_vote"("p_battle_id" "uuid", "p_voted_contender_id" "uuid", "p_vote_value" "battles"."vote_value_enum", "p_is_draw" boolean, "p_rationale" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_submit_vote"("p_battle_id" "uuid", "p_voted_contender_id" "uuid", "p_vote_value" "battles"."vote_value_enum", "p_is_draw" boolean, "p_rationale" "text") IS 'Canonical vote submission path. Atomically: 1) inserts into battles.votes (uq_votes_battle_voter prevents double-vote), 2) upserts battles.vote_aggregates, 3) increments battles.total_vote_count. Phase A fix: removed broken xp.events INSERT (wrong columns). XP award deferred to Phase C once xp rule_id for BATTLE_VOTED is known. Direct INSERT on battles.votes is restricted to service_role (authenticated policy dropped in A2).';



CREATE OR REPLACE FUNCTION "public"."fn_submit_vote"("p_battle_id" "uuid", "p_voted_contender_id" "uuid", "p_vote_value" "text", "p_is_draw" boolean DEFAULT false, "p_rationale" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_voter_lenser_id  uuid;
  v_vote_id   uuid;
BEGIN
  v_voter_lenser_id := lensers.get_auth_lenser_id();

  -- Rate-limit: one vote per voter per battle per 60 s
  IF NOT battles.fn_check_vote_rate_limit(v_voter_lenser_id, p_battle_id) THEN
    RAISE EXCEPTION 'RATE_LIMIT: vote rate limit exceeded for battle %', p_battle_id
      USING ERRCODE = 'P0429';
  END IF;

  INSERT INTO battles.votes (
    battle_id,
    voter_lenser_id,
    voted_contender_id,
    vote_value,
    is_draw,
    rationale
  )
  VALUES (
    p_battle_id,
    v_voter_lenser_id,
    p_voted_contender_id,
    p_vote_value,
    p_is_draw,
    p_rationale
  )
  RETURNING id INTO v_vote_id;

  RETURN jsonb_build_object(
    'vote_id',   v_vote_id,
    'status',    'submitted',
    'battle_id', p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_submit_vote"("p_battle_id" "uuid", "p_voted_contender_id" "uuid", "p_vote_value" "text", "p_is_draw" boolean, "p_rationale" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_summarize_memory_profile"("p_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_profile     agents.memory_profiles;
  v_count       integer;
  v_last_at     timestamptz;
  v_scope_stats jsonb;
BEGIN
  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  SELECT COUNT(*), MAX(created_at)
    INTO v_count, v_last_at
    FROM agents.memories
   WHERE profile_id = p_profile_id AND is_redacted = false;

  SELECT COALESCE(jsonb_object_agg(scope, c), '{}'::jsonb)
    INTO v_scope_stats
    FROM (
      SELECT scope, COUNT(*) AS c
        FROM agents.memories
       WHERE profile_id = p_profile_id AND is_redacted = false
       GROUP BY scope
    ) s;

  RETURN jsonb_build_object(
    'profile_id',      p_profile_id,
    'count',           COALESCE(v_count, 0),
    'last_written_at', v_last_at,
    'scopes',          v_scope_stats
  );
END;
$$;


ALTER FUNCTION "public"."fn_summarize_memory_profile"("p_profile_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_summarize_memory_profile"("p_profile_id" "uuid") IS 'Stub summary returning counts and last write. Replaceable by an LLM/embedding-backed summarizer behind the same signature (Open-Closed).';



CREATE OR REPLACE FUNCTION "public"."fn_switch_active_lenser"("p_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'agents', 'auth'
    AS $$
DECLARE
  v_human_id          uuid;
  v_current_active_id uuid;
  v_from_ai_lenser_id uuid;
  v_target_profile_id uuid;
  v_to_ai_lenser_id   uuid;
BEGIN
  SELECT p.id INTO v_human_id
  FROM lensers.profiles p
  WHERE p.user_id = auth.uid()
    AND p.type    = 'human'
    AND p.status  = 'active'
  LIMIT 1;

  IF v_human_id IS NULL THEN
    RAISE EXCEPTION 'No active human profile found for this user';
  END IF;

  SELECT pref.active_lenser_id INTO v_current_active_id
  FROM lensers.preferences pref
  WHERE pref.lenser_id = v_human_id
  LIMIT 1;

  SELECT al.id INTO v_from_ai_lenser_id
  FROM agents.ai_lensers al
  JOIN lensers.profiles ap ON ap.id = al.profile_id
  WHERE ap.id = v_current_active_id
  LIMIT 1;

  IF p_lenser_id = v_human_id THEN
    UPDATE lensers.preferences
    SET active_lenser_id = NULL,
        updated_at       = now()
    WHERE lenser_id = v_human_id;

    IF v_from_ai_lenser_id IS NOT NULL THEN
      INSERT INTO agents.workspace_switches (human_lenser_id, from_ai_lenser_id, to_ai_lenser_id)
      VALUES (v_human_id, v_from_ai_lenser_id, NULL);
    END IF;

    RETURN;
  END IF;

  SELECT ai_p.id, al.id
  INTO v_target_profile_id, v_to_ai_lenser_id
  FROM agents.ownerships o
  JOIN agents.ai_lensers al ON al.id = o.ai_lenser_id
  JOIN lensers.profiles ai_p ON ai_p.id = al.profile_id
  WHERE o.owner_lenser_id = v_human_id
    AND (ai_p.id = p_lenser_id OR al.id = p_lenser_id)
    AND o.role = 'owner'
    AND o.revoked_at IS NULL
    AND ai_p.status = 'active'
  LIMIT 1;

  IF v_target_profile_id IS NULL THEN
    RAISE EXCEPTION 'Cannot switch: profile not found or not owned'
      USING ERRCODE = '42501';
  END IF;

  UPDATE lensers.preferences
  SET active_lenser_id = v_target_profile_id,
      updated_at       = now()
  WHERE lenser_id = v_human_id;

  INSERT INTO agents.workspace_switches (human_lenser_id, from_ai_lenser_id, to_ai_lenser_id)
  VALUES (v_human_id, v_from_ai_lenser_id, v_to_ai_lenser_id);
END;
$$;


ALTER FUNCTION "public"."fn_switch_active_lenser"("p_lenser_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_switch_active_lenser"("p_lenser_id" "uuid") IS 'Switches the authenticated user''s active workspace to the given lenser ID. Accepts the human profile id, an owned AI profile id, or that owned AI lenser runtime id. Stores AI selection in lensers.preferences.active_lenser_id as the profile id and appends agents.workspace_switches audit rows.';



