CREATE OR REPLACE FUNCTION "public"."fn_tag_workflow_run"("p_run_id" "uuid", "p_tag" "text", "p_severity" "text" DEFAULT 'info'::"text", "p_node_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_caller_id uuid := lensers.get_auth_lenser_id();
  v_tag_id    uuid;
BEGIN
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF p_severity NOT IN ('info', 'warn', 'critical') THEN
    RAISE EXCEPTION 'invalid severity: %', p_severity USING ERRCODE = 'check_violation';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    WHERE r.id = p_run_id
      AND r.triggered_by = v_caller_id
  ) THEN
    RAISE EXCEPTION 'workflow_run % not found or not owned by caller', p_run_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  INSERT INTO lenses.workflow_run_tags (run_id, tag, severity, node_id, metadata)
  VALUES (p_run_id, p_tag, p_severity, p_node_id, p_metadata)
  RETURNING id INTO v_tag_id;

  RETURN v_tag_id;
END;
$$;


ALTER FUNCTION "public"."fn_tag_workflow_run"("p_run_id" "uuid", "p_tag" "text", "p_severity" "text", "p_node_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_tag_workflow_run"("p_run_id" "uuid", "p_tag" "text", "p_severity" "text", "p_node_id" "uuid", "p_metadata" "jsonb") IS 'Classifies a workflow run with a tag (info|warn|critical). Owner-gated. Called by the browser executor + CF Worker to mark moderation_blocked / contract_violated / idempotent_replay / partial_success / high_token_usage runs. See docs/reference/workflows/execution-engine.md §Observability.';



CREATE OR REPLACE FUNCTION "public"."fn_tags_get_cloud"("p_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "slug" "text", "name" "text", "visibility" "text", "created_at" timestamp with time zone, "created_count" bigint, "viewed_count" bigint, "reacted_count" bigint, "total_usage" bigint, "trend_score_7d" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'content', 'analytics'
    AS $$
  SELECT
    id,
    slug,
    name,
    visibility,
    created_at,
    created_count,
    viewed_count,
    reacted_count,
    total_usage,
    trend_score_7d
  FROM vw_tags_public_stats
  ORDER BY trend_score_7d DESC NULLS LAST, total_usage DESC NULLS LAST
  LIMIT LEAST(p_limit, 100);
$$;


ALTER FUNCTION "public"."fn_tags_get_cloud"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_tags_search"("p_query" "text", "p_lang" "text" DEFAULT 'en'::"text", "p_limit" integer DEFAULT 5) RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "visibility" "text", "total_usage" bigint, "lang_match" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    t.id,
    COALESCE(tr_lang.name, tr_en.name, t.slug) AS name,
    t.slug,
    t.visibility::text,
    COALESCE(s.total_usage, 0)                  AS total_usage,
    (tr_lang.tag_id IS NOT NULL)                AS lang_match
  FROM content.tags t
  LEFT JOIN content.tag_translations tr_lang
    ON tr_lang.tag_id = t.id AND tr_lang.language_code = p_lang
  LEFT JOIN content.tag_translations tr_en
    ON tr_en.tag_id = t.id AND tr_en.language_code = 'en'
  LEFT JOIN vw_tags_public_stats s
    ON s.id = t.id
  WHERE
    t.visibility = 'public'
    AND (
      COALESCE(tr_lang.name, tr_en.name, t.slug) ILIKE '%' || p_query || '%'
      OR t.slug ILIKE '%' || p_query || '%'
    )
  ORDER BY
    lang_match DESC,
    CASE
      WHEN LOWER(COALESCE(tr_lang.name, tr_en.name, t.slug)) = LOWER(p_query) THEN 0
      ELSE 1
    END,
    COALESCE(s.total_usage, 0) DESC
  LIMIT p_limit;
$$;


