CREATE OR REPLACE FUNCTION "public"."fn_trg_votes_velocity_check"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
BEGIN
  -- Skip rate-limit check for service_role and postgres (seed/admin inserts)
  IF auth.role() = 'authenticated' THEN
    PERFORM public.fn_check_vote_velocity(NEW.voter_lenser_id);
  END IF;
  RETURN NEW;
END;
$$;


